#'
#' Compute CIGVAR impulse responses with confidence bands
#'
#' Compute impulse response functions (IRFs) for an estimated CIGVAR model and
#' bootstrap confidence bands for the selected response specification.
#'
#' @param res A fitted CIGVAR object, typically returned by `cigvar_estimate()`.
#' @param nstep Integer scalar giving the number of IRF horizons.
#' @param comb Numeric vector of length `m * n` defining a combined shock, such
#'   as a global shock, regional shock, or concerted action.
#' @param irf Character string specifying the IRF type. Supported values are
#'   `"gen"`, `"chol"`, `"chol1"`, `"gen1"`, and `"comb1"`.
#' @param runs Integer scalar giving the number of bootstrap replications used
#'   to construct confidence bands.
#' @param conf Numeric vector of tail probabilities used to form the bootstrap
#'   confidence interval.
#' @return A four-dimensional array of dimension `(m * n, m * n, nstep,
#'   length(conf) + 1)`. The first two dimensions index responses and impulses,
#'   the third indexes horizons, and the fourth contains the point estimate
#'   followed by the confidence bounds.
#' @examples
#'
#' n = 5
#' p = (1:15)*0; dim(p) = c(5,3)
#' p[,1] = 3; p[,2]=3;
#' p[2,1] = 2;  p[3,1] = 2
#' res_d = cigvar_data(m=2,n=5,p=p,T=500,type="const",DFYflag=0)
#' res_d$r_npo
#' res_d$check
#' res_e = cigvar_estimate(res_d)
#' res_e$Summary
#'
#' ### Impulse response function
#'
#' IRF_CB = irf_cigvar_cb(res=res_e,nstep=20,comb=NA,irf="gen1",runs=200,conf=c(0.05,0.95))
#'
#' dim(IRF_CB)
#' IRF_g = plot_irf(IRF_CB,Names=NA,response=c(1,4),impulse=c(1,2,3,4), ncol=4)
#'
#'
#'
#'
#' @export
irf_cigvar_cb <- function (res, nstep, comb, irf = c("gen", "chol", "chol1", "gen1", "comb1"), runs = 200, conf = c(0.05, 0.95))
{
  m = res$m
  n = res$n
  p = res$p
  T = dim(res$Y)[1]
  W = res$W
  r_npo = res$r_npo
  Ao = res$Ao
  Bo = res$Bo
  Go = res$G
  Co = res$Co
  Sigmao = res$Sigmao
  type = res$type
  X = res$X
  mu = res$mu
  DFYflag = res$DFYflag
  crk = res$crk
  Ncommfakt = res$Ncommfakt
  A = res$A
  uz = res$uz

  B = res$G
  neq = dim(B)[1]
  nvar = dim(B)[2]
  sigma = res$Sigmao
  response <- array(0, dim = c(neq, nvar, nstep, length(conf) + 1))
  response[, , , 1] <- irf_gvar(res, nstep, comb, irf)
  responseR <- array(0, dim = c(neq, nvar, nstep, runs))
  for (i in 1:runs) {
    Uo_run = rnorm_sigma(T, sigma)
    res_run = cigvar_data(m, n, p, T, W, r_npo = NA, Ao, Bo,Co, Uo = Uo_run, Sigmao = NA, type, X, mu,DFYflag,crk,Ncommfakt,A,uz)
    res_e = cigvar_estimate(res_run)
    B_run = res_e$G
    sigma_run = res_e$Sigmao
    responseR[, , , i] <- irf_gvar(res_e, nstep, comb, irf)
  }
  for (tt in 1:(nstep)) {
    for (i in 1:neq) {
      for (j in 1:nvar) {
        Ao
        response[i, j, tt, -1] = stats::quantile(responseR[i,j, tt, ], conf)
      }
    }
  }
  return(response)
}



#'
#' Compute CIVAR impulse responses with confidence bands
#'
#' Compute impulse response functions (IRFs) for an estimated CIVAR model and
#' bootstrap confidence bands for alternative identification schemes, including
#' permanent-transitory decompositions and exogenous-shock responses.
#'
#' @param res A fitted CIVAR object, typically returned by `civar_estimate()`.
#' @param nstep Integer scalar giving the number of IRF horizons.
#' @param comb Optional weighting matrix used for combined shocks. Use `NA` for
#'   standard CIVAR models without combined impulses.
#' @param irf Character string specifying the IRF type. Supported values are
#'   `"gen"`, `"chol"`, `"chol1"`, `"gen1"`, `"comb1"`, `"PTdecomp"`,
#'   `"ABSVAR"`, and `"irfX"`.
#' @param G Optional transformation matrix used for permanent-transitory
#'   decomposition.
#' @param A0 Optional identification matrix used for AB-structural
#'   identification.
#' @param B0 Optional identification matrix used for AB-structural
#'   identification.
#' @param Xshks Integer vector identifying the exogenous shocks used when
#'   `irf = "irfX"`.
#' @param runs Integer scalar giving the number of bootstrap replications used
#'   to construct confidence bands.
#' @param conf Numeric vector of tail probabilities used to form the bootstrap
#'   confidence interval.
#' @return A four-dimensional array of dimension `(n, n, nstep, length(conf) +
#'   1)`. The dimensions correspond to responses, impulses, horizons, and the
#'   point estimate plus confidence bounds.
#'
#' @examples
#' res_d = civar_data(n=4,p=2,T=84,Co=matrix(c(1,1,1,1),4,1)*0,type="none",crk=1)
#' res_e = civar_estimate(res=res_d)
#' res_e$Summary
#'
#' IRF_CB = irf_civar_cb(res=res_e, nstep=20, comb=NA, irf = "gen1", runs = 20, conf = c(0.05, 0.95))
#' IRF_g = plot_irf(IRF_CB)
#'
#' IRF_CB = irf_civar_cb(res=res_e, nstep=30, comb=NA, irf = "PTdecomp", G = NA, A0=NA, B0=NA,
#'                        runs = 20, conf = c(0.05, 0.95))
#' IRF_g = plot_irf(IRF_CB)
#' # The first three shocks have permanent effects,
#' # while the fourth shock does not have a permanent effect.
#'
#' T=100
#' X=matrix(rnorm(2*T),T,2)
#' res_d = var_data(n=3,p=2,T=T,Co=matrix(c(0,0,0,1,2,3,3,2,1),3,3), type="exog0",X=X)
#' res_e = var_estimate(res=res_d)
#' res_d$Co
#' res_e$Summary
#' IRF_CB = irf_var_cb(res=res_e,nstep=20, comb=NA, irf = "irfX", Xshks=c(1:2),
#'                      runs = 100, conf = c(0.05, 0.95))
#' IRF_list <- plot_irf(IRF_CB, Names=c("Y1","Y2","Y3"), INames=c("X1","X2"),
#'                       response = c(1:3), impulse = c(1:3), n = 3)
#'
#' @export
irf_civar_cb <- function(res, nstep, comb, irf = c("gen", "chol", "chol1", "gen1", "comb1", "PTdecomp", "ABSVAR", "irfX"), G = NA, A0 = NA, B0 = NA, Xshks = NA, runs = 200, conf = c(0.05, 0.95))
{
  n     = res$n
  p     = res$p
  T     = dim(res$Y)[1]
  A     = res$A
  B     = res$B
  Co    = res$Co
  C1    = res$C1
  type  = res$type
  X     = res$X
  crk   = res$crk
  neq   = dim(B)[1]
  nvar  = dim(B)[2]
  sigma = res$Sigma
  Uo    = res$resid
  G = NA
  if (irf=="PTdecomp") {
    crk = res$crk

    alpha  =  (as.matrix(res$tst$estimation$coefficients[1:crk,]))
    if (dim(alpha)[1]<dim(alpha)[2]) {
      alpha = t(alpha)
    }
    G     = t(cbind(alpha_perpf(alpha),alpha))
  }
  if (irf == "irfX") { Xshk = t(Co[,1+Xshks]) }
  response <- array(0, dim = c(neq, nvar, nstep, length(conf) + 1))
  response[, , , 1] <- irf_from_params(B = B, sigma = sigma, nstep, comb, irf, G=G,A0=A0,B0=B0,smat=NA,Xshk=Xshk)
  responseR         <- array(0, dim = c(neq, nvar, nstep, runs))

  for (i in 1:runs) {
    Uo_run = rnorm_sigma(T, sigma)
    #Index = c(1:T)
    #resample  = sample(Index)
    #Uo_run    = Uo[resample,]
    res_drun  = civar_data(n, p, T, r_np = NA, A = NA, B, Co, C1, U = Uo_run, Sigma = NA, type, X, mu = NA, Yo = NA, crk)
    res_erun  = civar_estimate(res_drun)
    B_run     = res_erun$B
    Co_run    = res_erun$Co
    sigma_run = res_erun$Sigma

    G_run = NA
    if (irf=="PTdecomp") {
      crk = res$crk

      alpha_run  =  (as.matrix(res_erun$tst$estimation$coefficients[1:crk,]))
      if (dim(alpha_run)[1]<dim(alpha_run)[2]) {
        alpha_run = t(alpha_run)
      }
      G_run     = t(cbind(alpha_perpf(alpha_run),alpha_run))
    }

    if ( irf =="ABSVAR") {
      x0 = stats::rnorm(n*(n+1)/2)
      ABD <- absvar(x0,A0,B0,Sigma=sigma_run)
      A0_run = ABD[[1]]
      B0_run = ABD[[2]]
    }   else {
      A0_run = NA
      B0_run = NA
    }
    if (irf == "irfX") { Xshk = t(Co_run[,1+Xshks]) }
    responseR[, , , i] <- irf_from_params(B = B_run, sigma = sigma_run, nstep, comb, irf, G=G_run,A0=A0_run,B0=B0_run,smat=NA,Xshk=Xshk)
  }
  for (tt in 1:(nstep)) {
    for (i in 1:neq) {
      for (j in 1:nvar) {
        response[i, j, tt, -1] = stats::quantile(responseR[i,j, tt, ], conf)

      }
    }
  }
  #response[, , , 1] = responseR[,,,5]
  return(response)
}



#'
#' Compute GVAR impulse responses
#'
#' Compute impulse response functions (IRFs) for an estimated GVAR model under
#' alternative identification schemes and combined-shock specifications.
#'
#' @param res A fitted GVAR object, typically returned by `gvar_estimate()`.
#' @param nstep Integer scalar giving the number of IRF horizons.
#' @param comb Numeric vector of length `m * n` defining a combined shock, such
#'   as a global shock, regional shock, or concerted action.
#' @param irf Character string specifying the IRF type. Supported values are
#'   `"gen"`, `"chol"`, `"chol1"`, `"gen1"`, and `"comb1"`.
#' @return A three-dimensional array of dimension `(m * n, m * n, nstep)`,
#'   indexed by responses, impulses, and horizons.
#' @examples
#'
#' X1 = matrix(1,200,1)
#' X2 = matrix(rnorm(200),200,1)
#' X3 = matrix(rnorm(200),200,1)
#' X4 = matrix(rnorm(200),200,1)
#' X  = cbind(X1,X2,X3,X4)
#' dim(X) = c(200,1,4)
#'
#' n = 4
#' p = (1:12)*0; dim(p) = c(4,3);p[,1] = 2; p[,2]=2; p[,3]=1;
#' res_d = gvar_data(m=2,n=4,p=p,T=200,type="exog0",X=X)
#' res_e = gvar_estimate(res=res_d)
#' IRF = irf_gvar(res_e,nstep=10,comb=NA,irf="gen")
#' IRF_CB = irf_gvar_cb(res_e,nstep=10,comb=NA,irf="gen",runs=200,conf=c(0.05,0.95))
#' dim(IRF_CB)
#' IRF_g = plot_irf(IRF_CB,Names=NA,response=c(1,4),impulse=c(1,2,3,4), ncol=4)
#'
#' @export
#' @keywords internal
#'
irf_gvar = function(res,nstep,comb,irf=c("gen","chol","chol1","gen1","comb1")) {
  B 	= res$G
    neq 	= dim(B)[1]
  nvar	= dim(B)[2]
  sigma = res$Sigma
    response <- array(0,dim=c(neq,nvar,nstep));
    response <- irf_from_params(B,sigma,nstep,comb,irf=irf)
  return(response)
}



#'
#' Compute GVAR impulse responses with confidence bands
#'
#' Compute impulse response functions (IRFs) for an estimated GVAR model and
#' bootstrap confidence bands for the selected identification scheme.
#'
#' @param res A fitted GVAR object, typically returned by `gvar_estimate()`.
#' @param nstep Integer scalar giving the number of IRF horizons.
#' @param comb Numeric vector of length `m * n` defining a combined shock, such
#'   as a global shock, regional shock, or concerted action.
#' @param irf Character string specifying the IRF type. Supported values are
#'   `"gen"`, `"chol"`, `"chol1"`, `"gen1"`, and `"comb1"`.
#' @param runs Integer scalar giving the number of bootstrap replications used
#'   to construct confidence bands.
#' @param conf Numeric vector of tail probabilities used to form the bootstrap
#'   confidence interval.
#' @return A four-dimensional array of dimension `(m * n, m * n, nstep,
#'   length(conf) + 1)`. The first two dimensions index responses and impulses,
#'   the third indexes horizons, and the fourth contains the point estimate
#'   followed by the confidence bounds.
#' @examples
#' n = 5
#' p = (1:15)*0; dim(p) = c(5,3)
#' p[,1] = 2; p[,2]=1;
#' res_d = gvar_data(m=2,n=5,p=p,T=100,type="const")
#' max(res_d$Y)
#' dim(res_d$Y)
#' res_e = gvar_estimate(res = res_d)
#' res_e$Summary
#'
#' IRF_CB = irf_gvar_cb(res_e,nstep=10,comb=NA,irf="gen",runs=200,conf=c(0.05,0.95))
#' dim(IRF_CB)
#' IRF_g = plot_irf(IRF_CB,Names=NA,response=c(1,4),impulse=c(1,2,3,4), ncol=4)
#'
#' @export
irf_gvar_cb = function(res, nstep, comb, irf = c("gen", "chol", "chol1", "gen1", "comb1"), runs = 200, conf = c(0.05, 0.95)) {
  m = res$m
  n = res$n
  p = res$p
  T = dim(res$Y)[1]
  W = res$W
  Ao = res$Ao
  Bo = res$Bo
  Go = res$G
  Co = res$Co
  type = res$type
  X = res$X
  mu = res$mu
  
  B = res$G
  neq = dim(B)[1]
  nvar = dim(B)[2]
  sigma = res$Sigmao
  response <- array(0, dim = c(neq, nvar, nstep, length(conf) + 1))
  response[,,,1] <- irf_gvar(res, nstep, comb, irf)
  responseR <- array(0, dim = c(neq, nvar, nstep, runs))
  
  for (i in 1:runs) {
    Uo_run = rnorm_sigma(T, sigma)
    res_run = gvar_data(m, n, p, T, W, r_npo = NA, Ao, Bo, Co, Uo = Uo_run, Sigmao = NA, type, X, mu)
    res_e = gvar_estimate(res_run)
    B_run = res_e$G
    sigma_run = res_e$Sigmao
    responseR[,,,i] = irf_gvar(res_e, nstep, comb, irf)
  }
  
  responseR[,,,1] = response[,,,1]
  
  for (tt in 1:(nstep)) {
    for (i in 1:neq) {
      for (j in 1:nvar) {
        response[i, j, tt, -1] = stats::quantile(responseR[i, j, tt, ], conf)
      }
    }
  }
  
  return(response)
}



#'
#' Compute MRCIGVAR impulse responses with confidence bands
#'
#' Compute impulse response functions (IRFs) for an estimated MRCIGVAR model and
#' bootstrap confidence bands for a selected state configuration.
#'
#' @param res A fitted MRCIGVAR object, typically returned by
#'   `mrcigvar_estimate()`.
#' @param nstep Integer scalar giving the number of IRF horizons.
#' @param comb Numeric vector defining a combined or concerted-action shock.
#' @param state Integer vector of length `n` specifying the state assigned to
#'   each country.
#' @param irf Character string specifying the IRF type. Supported values are
#'   `"gen"`, `"chol"`, `"chol1"`, `"gen1"`, and `"comb1"`.
#' @param runs Integer scalar giving the number of bootstrap replications.
#' @param conf Numeric vector of tail probabilities used to form the bootstrap
#'   confidence interval.
#' @param NT Integer scalar giving the number of simulated IRF scenarios.
#' @return A list whose first element is a four-dimensional array of dimension
#'   `(m * n, m * n, nstep, length(conf) + 1)` containing the point estimate and
#'   confidence bounds. The remaining elements store bootstrap draws of model
#'   quantities generated during the procedure.
#'
#' @examples
#' m = 2
#' n = 3
#' p = c(2,2,2,2,2,2,2,2,2,2,0,0,0,0,0,2,2,2,2,2,2,2,2,2,2,0,0,0,0,0); dim(p) = c(5,3,2)
#' p = p[1:n,,]; p[,1,] = 3; p[,2,] = 2
#'
#' TH = c(1:n)*0; dim(TH) = c(1,n)
#' SESVI=rep(1,3,5)
#' r  = rep(1,n)
#'
#' ## case of n = 3, m = 2, S = 2    m: number of variables, n: number of countries
#'
#'
#' res_d <- mrcigvar_data(m=2,n=3,p=p,TH=TH,T=100,S=2, SESVI=c(1,3,5),r=rep(1,3),Ncommtrend=1)
#' max(abs(res_d$Y))
#' spectral_radius(res_d$Go[,,,2])
#' spectral_radius(res_d$Go[,,,1])
#' res_e  = mrcigvar_estimate(res=res_d)
#'
#' res_e$Summary
#'
#' IRF_CB = irf_mrcigvar_cb(res=res_e, nstep=10, comb=NA, state = c(2,1,1), irf = "gen1",runs=20,
#'  conf = c(0.05, 0.95), NT = 1)
#'
#' str(IRF_CB)
#'
#' IRF_g = plot_irf(IRF_CB[[1]])
#'
#' @export
#'
irf_mrcigvar_cb <- function (res, nstep, comb, state = c(2, 1), irf = c("gen", "chol", "chol1", "gen1", "comb1"), runs = 200, conf = c(0.05, 0.95), NT = 1)
{
  m = res$m
  n = res$n
  p = res$p
  if (length(p) > 1)
    pp = max(p[, 1:2, ])
  else pp = p
  T = dim(res$Y)[1] * NT
  W = res$W
  S = res$S
  SV = res$SV
  SESVI = res$SESVI
  TH = res$TH
  Ao = res$Ao
  Bo = res$Bo
  Co = res$Co
  Go = res$Go
  Sigmao = res$Sigmao
  GoColect = array(0, c(dim(Go), runs))
  BoColect = array(0, c(dim(Bo), runs))
  AoColect = array(0, c(dim(Ao), runs))
  UoColect = array(0, c(T, m * n, S, runs))
  YColect = array(0, c(T, m * n, runs))
  type = res$type
  X = res$X
  mu = res$mu
  B = bo_ao_ws2_gs(Bo, Ao, W, m, n, pp, state)
  neq = dim(B)[1]
  nvar = dim(B)[2]
  sigma = res$Sigmao
  response <- array(0, dim = c(neq, nvar, nstep, length(conf) +
                                 1))
  sigmaNPDS = sigma_npd(res, state)
  sigmaNPD1 = sigma_npd(res, rep(1, n))
  sigmaNPD2 = sigma_npd(res, rep(2, n))
  Sigmao_sim = Sigmao * 0
  Sigmao_sim[, , 1] = sigmaNPD1
  Sigmao_sim[, , 2] = sigmaNPD2
  response[, , , 1] <- irf_mrcigvar(res, nstep, comb, state, irf)
  responseR <- array(0, dim = c(neq, nvar, nstep, runs))
  Uo_run = array(0, c(T, n * m, S))
  for (i in 1:runs) {
    for (s in 1:S) Uo_run[, , s] = rnorm_sigma(T, sigmaNPDS)
    if (length(p) > 1) {
      res_run = mrcigvar_data(m, n, p, T, S, W, SESVI, TH, res$Go, Sigmao = Sigmao_sim, SV, type = "none")
      res_e = mrcigvar_estimate(res_run)
    }
    if (length(p) == 1) {
      res_run = mrgvar_data(m, n, p, T, S, W, SESVI, TH, res$Go, Ao = NA, Bo = NA, Sigmao = NA, Uo = Uo_run, SV, type, res$Co, X)
      res_e = mrcigvar_estimate(res_run)
    }
    responseR[, , , i] <- irf_mrgvar(res_e,state, nstep, comb, irf,G=NA,smat=NA,sigmaNPDS=sigma_npd(res_e, state))
    GoColect[, , , , i] <- res_e$Go
    BoColect[, , , , , i] <- res_e$Bo
    AoColect[, , , , , i] <- res_e$Ao
    UoColect[, , , i] <- res_run$Uo
    YColect[, , i] <- res_run$Y
  }
  for (tt in 1:(nstep)) {
    for (i in 1:neq) {
      for (j in 1:nvar) {
        response[i, j, tt, -1] = stats::quantile(responseR[i, j, tt, ], conf)
      }
    }
  }
  return(list(response, GoColect, BoColect, AoColect, UoColect, YColect))
}



#'
#' Compute MRCIGVAR impulse responses
#'
#' Compute impulse response functions (IRFs) for an estimated MRCIGVAR model at
#' a specified state configuration.
#'
#' @param res A fitted MRCIGVAR object, typically returned by
#'   `mrcigvar_estimate()`.
#' @param nstep Integer scalar giving the number of IRF horizons.
#' @param comb Numeric vector defining a combined or concerted-action shock.
#' @param state Integer vector of length `n` specifying the state assigned to
#'   each country.
#' @param irf Character string specifying the IRF type. Supported values are
#'   `"gen"`, `"chol"`, `"chol1"`, `"gen1"`, and `"comb1"`.
#' @param sigmaNPDS Optional state-dependent covariance matrix. When `NA`, the
#'   matrix is computed from `res` and `state`.
#' @return A three-dimensional array of dimension `(m * n, m * n, nstep)`,
#'   indexed by responses, impulses, and horizons.
#'
#' @examples
#' m = 2
#' n = 3
#' p = c(2,2,2,2,2,2,2,2,2,2,0,0,0,0,0,2,2,2,2,2,2,2,2,2,2,0,0,0,0,0); dim(p) = c(5,3,2)
#' p = p[1:n,,]; p[,1,] = 3; p[,2,] = 2
#'
#' TH = c(1:n)*0; dim(TH) = c(1,n)
#' SESVI=rep(1,3,5)
#' r  = rep(1,n)
#'
#' ## case of n = 3, m = 2, S = 2    m: number of variables, n: number of countries
#'
#' res_d <- mrcigvar_data(m=2,n=3,p=p,TH=TH,T=300,S=2, SESVI=c(1,3,5),r=rep(1,3),Ncommtrend=1)
#' max(abs(res_d$Y))
#' spectral_radius(res_d$Go[,,,2])
#' spectral_radius(res_d$Go[,,,1])
#' res_e  = mrcigvar_estimate(res=res_d)
#'
#' res_e$Summary
#'
#' IRFF2 = irf_mrcigvar(res=res_e,nstep=10,comb=NA,state=c(2,2,2),irf='gen')
#' plot(IRFF2[1,1,],type="l")
#'
#' @export
#' @keywords internal
irf_mrcigvar <- function(res, nstep, comb, state = state, irf = c("gen", "chol", "chol1", "gen1", "comb1"), sigmaNPDS = NA) {
  neq <- dim(res$Go)[1]
  nvar <- dim(res$Go)[2]
  m <- res$m
  n <- res$n
  p <- res$p
  if (length(p) > 1) pp = max(p[, 1:2, ]) else pp = p
  Bo <- res$Bo
  Ao <- res$Ao
  W <- res$W
  B <- bo_ao_ws2_gs(Bo, Ao, W, m, n, pp, state)
  if (anyNA(sigmaNPDS)) sigma = sigma_npd(res, state) else sigma = sigmaNPDS
  response <- array(0, dim = c(neq, nvar, nstep))
  response <- irf_from_params(B, sigma, nstep, comb, irf = irf)
  return(response)
}



#'
#' Compute generalized impulse responses for MRCIGVAR models
#'
#' Compute generalized impulse response functions (GIRFs) for an estimated
#' MRCIGVAR model by comparing average simulated paths with and without an
#' imposed shock across repeated simulation runs.
#'
#' For a shock vector `SHCK`, the GIRF is defined as
#' `mean(Y(SHCK)) - mean(Y(resid))`.
#'
#' See H.H. Pesaran and Y. Shin (1998) Generalized impulse response analysis in linear multivariate 
#' models, Economics Letters, 58(1) p. 17-29.
#'
#' @param res A fitted MRCIGVAR object, typically returned by
#'   `mrcigvar_estimate()`.
#' @param shock Numeric vector of length `m * n` defining the impulse.
#' @param R Integer scalar giving the number of simulation runs used to average
#'   over random effects.
#' @param nstep Integer scalar giving the number of response horizons.
#' @param Omega_hist Matrix of initial values used to start the simulation. If
#'   `NA`, the most recent observations are used; if `0`, zero initial values
#'   are used.
#' @param resid_method Character string specifying how residual draws are
#'   generated. Supported values are `"resid"` and `"parametric"`.
#' @return A three-dimensional array of dimension `(m * n, m * n, nstep + 1)`,
#'   indexed by responses, impulses, and horizons.
#'
#' @examples
#' \dontrun{
#' m = 2
#' n = 3
#' p = c(2,2,2,2,2,2,2,2,2,2,0,0,0,0,0,2,2,2,2,2,2,2,2,2,2,0,0,0,0,0)
#' dim(p) = c(5,3,2)
#' p = p[1:n,,]
#' p[,1,] = 3
#' p[,2,] = 2
#'
#' TH = c(1:n)*0
#' dim(TH) = c(1,n)
#' SESVI = rep(1,3,5)
#' r = rep(1,n)
#'
#' ## case of n = 3, m = 2, S = 2    m: number of variables, n: number of countries
#' res_d <- mrcigvar_data(m=2, n=3, p=p, TH=TH, T=200, S=2, SESVI=c(1,3,5), r=rep(1,3), Ncommtrend=1)
#' max(abs(res_d$Y))
#' spectral_radius(res_d$Go[,,,2])
#' spectral_radius(res_d$Go[,,,1])
#' res_e  = mrcigvar_estimate(res=res_d)
#'
#' spectral_radius(res_e$Go[,,,2])
#' spectral_radius(res_e$Go[,,,1])
#'
#' plot(ts(res_d$Y))
#'
#' if (!((max(Mod(spectral_radius(res_e$Go[,,,1])))>1.0001)|
#'  (max(Mod(spectral_radius(res_e$Go[,,,2])))>1.0001)) ) {
#'   GIRF <- girf_mrcigvar_rm(res=res_e, shock=c(1,1,1,1,1,1), R=100, nstep=10, Omega_hist=NA,
#'   resid_method="parametric")
#'   GIRF_CB <- girf_mrcigvar_rm_cb(res=res_e, shock=c(1,1,1,1,1,1), R=100, nstep=10, Omega_hist=NA,
#'   resid_method="parametric", conf=c(0.05,0.95), N=100)
#'   IRF_g = plot_irf(GIRF_CB)
#'  }
#' }
#'
#' @export
#' @keywords internal
girf_mrcigvar_rm <- function(res, shock, R, nstep, Omega_hist=NA, resid_method) {
  ####  this function generate the impulse response function of MRVAR with regime migration
  ####
  ####                  GIRF(shock=SHCK) = mean(Y(resid)) - mean(Y(SHCK))
  ####
  ####
  #### RES is the output of MRVAREST1
  n 		  = res$n
  m 		  = res$m
  p 		  = res$p
  d		    = res$d
  S 		  = res$S
  SESVI	  = res$SESVI
  TH		  = res$TH
  Go      = res$Go
  Bo		  = res$Bo
  Ao      = res$Ao
  Co		  = res$Co
  Sigmao  = res$Sigmao
  W       = res$W
  type	  = res$type
  SV      = res$SV
  P       = max(d,p)
  X 		  = res$X; if (!anyNA(X)) X = X[1:(P+nstep+1),];
  Yo		  = res$Yo
  Uo      = res$Uo
  TT      = dim(res$Y)[1]
  d       = res$d
  IRF 	  = list()
  YR      = list()
  YS      = list()
  residR  <-  list()
  residS  <-  residR

  if (anyNA(Omega_hist)) Omega_hist = res$Y[(dim(res$Y)[1]-P+1):dim(res$Y)[1],,drop=FALSE]
  state <- as.numeric(Omega_hist[P-d+1,SESVI]>TH) + 1

  #R 		= 400
  #shock       = (1:n)/(1:n)

  DIMresid    = dim(Uo)
  if (length(DIMresid) == 3)  residI = Uo[1:(P+1+nstep),,]*0
  if (length(DIMresid) == 2)  residI = Uo[1:(P+1+nstep),]*0
  shock_mat = matrix(0,m*n,m*n)
  Sigma_s = sigma_npd(res,state)

  shock_mat = Sigma_s%*%solve(diag(diag(Sigma_s)))%*%diag(shock)

  residI    = array(0,c(P+1+nstep,m*n,m*n,DIMresid[3]))

  residI    = array(0,c(P+1+nstep,m*n,m*n,DIMresid[3]))

  Yo = Omega_hist
  YR = array(0,c(P+1+nstep,m*n,m*n))
  YS <- YR
  MYS <- YS
  MYR <- YS
  GIRF <- array(0,c(m*n,m*n,nstep+1))

  for (i in 1:R) {
    if ( resid_method=="resid" ) {
      if (length(DIMresid) == 3)  {
        for (k in 1:(m*n)) {
          residI[,,k,]  = Uo[sample_n_out_of_t(P+nstep+1,DIMresid[1]),,];
        }
      }
    }
    if ( resid_method=="parametric" ) {
      if (length(DIMresid) == 3)  {
        for (k in 1:(m*n)) {
          for (s in 1:S)   residI[,,k,s] = rnorm_sigma(P+nstep+1,Matrix::nearPD(Sigmao[,,s])[[1]])
        }
      }
    }

    residR[[i]] <- residI
    for (s in 1:S) {residI[P+1,,,s] <-shock_mat}
    residS[[i]] = residI

    for (k in 1:DIMresid[2]) {
      YR[,,k] = mrcigvar_data(m=m, n=n, p=p, T=(P+nstep+1), S=S, W=W, SESVI=SESVI, TH=TH, Go=Go, Ao=Ao, Bo=Bo, Sigmao=Sigmao, Uo=residR[[i]][,,k,], SV=SV, type=type, Co=Co, X=X, Yo=Yo, d=d)$Y
      YS[,,k] = mrcigvar_data(m=m, n=n, p=p, T=(P+nstep+1), S=S, W=W, SESVI=SESVI, TH=TH, Go=Go, Ao=Ao, Bo=Bo, Sigmao=Sigmao, Uo=residS[[i]][,,k,], SV=SV, type=type, Co=Co, X=X, Yo=Yo, d=d)$Y
    }

    MYR = MYR + 1/R*YR
    MYS = MYS + 1/R*YS

  }  # end of R loop
  ############## integrating out the disturbances
  for (i in 1:(m*n) ) {
    for (j in 1:(m*n)) {
      for (k in 1:(nstep+1)) GIRF[i,j,k] = MYS[P+k,i,j]-MYR[P+k,i,j]
    }
  }
  return(GIRF)
}



#'
#' Compute MRCIGVAR generalized impulse responses with confidence bands
#'
#' Compute generalized impulse response functions (GIRFs) for an estimated
#' MRCIGVAR model and bootstrap confidence bands for a user-specified shock.
#'
#' For a shock vector `SHCK`, the GIRF is defined as
#' `mean(Y(SHCK)) - mean(Y(resid))`.
#'
#' See H.H. Pesaran and Y. Shin (1998) Generalized impulse response analysis in linear multivariate 
#' models, Economics Letters, 58(1) p. 17-29.
#'
#' @param res A fitted MRCIGVAR object, typically returned by
#'   `mrcigvar_estimate()`.
#' @param shock Numeric vector of length `m * n` defining the impulse.
#' @param R Integer scalar giving the number of simulation runs used to average
#'   over random effects.
#' @param nstep Integer scalar giving the number of response horizons.
#' @param Omega_hist Matrix of initial values used to start the simulation.
#' @param resid_method Character string specifying how residual draws are
#'   generated. Supported values are `"resid"` and `"parametric"`.
#' @param conf Numeric vector of tail probabilities used to form the bootstrap
#'   confidence interval.
#' @param N Integer scalar giving the number of bootstrap replications.
#' @return A four-dimensional array of dimension `(m * n, m * n, nstep + 1,
#'   length(conf) + 1)` containing the point estimate and confidence bounds.
#'
#' @examples
#' m = 2
#' n = 3
#' p = c(2,2,2,2,2,2,2,2,2,2,0,0,0,0,0,2,2,2,2,2,2,2,2,2,2,0,0,0,0,0)
#' dim(p) = c(5,3,2)
#' p = p[1:n,,]
#' p[,1,] = 3
#' p[,2,] = 2
#'
#' TH = c(1:n)*0
#' dim(TH) = c(1,n)
#' SESVI = rep(1,3,5)
#' r = rep(1,n)
#'
#' ## case of n = 3, m = 2, S = 2    m: number of variables, n: number of countries
#' res_d <- mrcigvar_data(m=2, n=3, p=p, TH=TH, T=200, S=2, SESVI=c(1,3,5), r=rep(1,3), Ncommtrend=1)
#' max(abs(res_d$Y))
#' spectral_radius(res_d$Go[,,,2])
#' spectral_radius(res_d$Go[,,,1])
#' res_e <- mrcigvar_estimate(res=res_d)
#'
#' spectral_radius(res_e$Go[,,,2])
#' spectral_radius(res_e$Go[,,,1])
#'
#' plot(ts(res_d$Y))
#'
#' if (!((max(Mod(spectral_radius(res_e$Go[,,,1])))>1)|
#'  (max(Mod(spectral_radius(res_e$Go[,,,2])))>1)) ) {
#'   GIRF <- girf_mrcigvar_rm(res=res_e, shock=c(1,1,1,1,1,1), R=100, nstep=10, Omega_hist=NA,
#'   resid_method="parametric")
#'   GIRF_CB <- girf_mrcigvar_rm_cb(res=res_e, shock=c(1,1,1,1,1,1), R=100, nstep=10, Omega_hist=NA,
#'   resid_method="parametric", conf=c(0.05,0.95), N=100)
#'   IRF_g = plot_irf(GIRF_CB)
#' }
#'
#' @export
girf_mrcigvar_rm_cb <- function(res, shock, R, nstep, Omega_hist=NA, resid_method="parametric", conf, N) {
  ##### this is to generate bootstrap GIRF for MRCIGVAR with regime migrations
  #####
  n = res$n
  m = res$m
  p = res$p
  S = res$S
  SESVI = res$SESVI
  TH = res$TH
  Go = res$Go
  Bo = res$Bo
  Ao = res$Ao
  Co = res$Co
  Sigmao = res$Sigmao
  W = res$W
  type = res$type
  SV = res$SV
  X = res$X
  Yo = res$Yo
  d = res$d
  Uo = res$Uo
  T = dim(res$Y)[1]
  P = max(d, p)
  GIRF = (1:(m*n*n*m*(nstep+1)*N))*0
  dim(GIRF) = c(m*n, m*n, nstep+1, N)

  GIRFBd = (1:(m*n*n*m*(nstep+1)*(length(conf)+1)))*0
  dim(GIRFBd) = c(m*n, m*n, nstep+1, length(conf)+1)

  GIRFBd[,,,1] = girf_mrcigvar_rm(res, shock, R, nstep, Omega_hist, resid_method)

  for (i in 1:N) {
    res_run = mrcigvar_data_r(res)
    if (length(colnames(res_run$Y))==0) colnames(res_run$Y) = paste("res_runY", 1:ncol(res_run$Y), sep="")
    res_erun = mrcigvar_estimate(res_run)
    RF3 = girf_mrcigvar_rm(res=res_erun, shock, R, nstep, Omega_hist, resid_method)
    GIRF[,,,i] = RF3
  }

  for (tt in 1:(nstep+1)) {
    for (i in 1:(n*m)) {
      for (j in 1:(n*m)) {
        GIRFBd[i, j, tt, -1] = stats::quantile(GIRF[i, j, tt, ], conf)
      }
    }
  }
  return(GIRFBd)
}



#'
#' Compute MRCIVAR impulse responses with confidence bands
#'
#' Compute impulse response functions (IRFs) for an estimated MRCIVAR model and
#' bootstrap confidence bands for each regime.
#'
#' @param res_e A fitted MRCIVAR object, typically returned by
#'   `mrcivar_estimate()`.
#' @param nstep Integer scalar giving the number of IRF horizons.
#' @param irf Character string specifying the IRF type. Supported values are
#'   `"gen"`, `"chol"`, `"chol1"`, `"gen1"`, and `"comb1"`.
#' @param runs Integer scalar giving the number of bootstrap replications.
#' @param comb Numeric vector defining a combined or concerted-action shock.
#' @param G Optional transformation matrix used in permanent-transitory
#'   decompositions.
#' @param smat Optional explicit shock-decomposition matrix.
#' @param conf Numeric vector of tail probabilities used to form the bootstrap
#'   confidence interval.
#' @return A list whose first two elements are four-dimensional arrays
#'   containing the point estimate and confidence bounds for regimes 1 and 2.
#'   Remaining elements store bootstrap draws of model quantities.
#'
#' @examples
#' n = 10
#'
#' Sigma = 1:(n*n*2)
#' dim(Sigma) = c(n,n,2)
#' Sigma[,,1] = diag(n)
#' Sigma[,,2] = diag(n)
#' p = matrix(0,2,2)
#' p[,1] = c(3,3)
#' res_d = mrcivar_data(n=n, p=p, T=250, S=2, SESVI=1, TH=0, Sigmao=Sigma, type="const", r=2)
#' max(abs(res_d$Y))
#' res_e = mrcivar_estimate(res=res_d)
#'
#' if (! max(Mod(spectral_radius(res_e$Bo[,,,1])), Mod(spectral_radius(res_e$Bo[,,,2])) ) > 1.0001 ) {
#'   IRF = irf_mrcivar_cb(res_e, nstep=20, irf="gen1", runs=100, comb=NA, G=NA, conf=c(0.05,0.95))
#'   IRF_g1 <- plot_irf(IRF[[1]])        # irf of regime 1
#'   IRF_g2 <- plot_irf(IRF[[2]])         # irf of regime 2
#' }
#'
#' @export
irf_mrcivar_cb = function (res_e, nstep = 20, irf = c("gen", "gen1"), runs = 100, comb = NA, G = NA, smat=NA, conf = c(0.05, 0.95))
{
  IRF1 = irf_from_params(B = res_e$Bo[, , , 1], sigma = res_e$Sigma[,, 1], nstep = nstep, comb = NA, irf = irf, G = NA, smat=NA)
  IRF2 = irf_from_params(B = res_e$Bo[, , , 2], sigma = res_e$Sigma[,, 2], nstep = nstep, comb = NA, irf = irf, G = NA, smat=NA)
  n = res_e$n
  p = res_e$p
  T = dim(res_e$Y)[1]
  S = res_e$S
  SV = res_e$SV
  SESVI = res_e$SESVI
  TH = res_e$TH
  Sigmao = res_e$Sigmao
  Bo = res_e$Bo
  Co = res_e$Co
  type = res_e$type
  r = res_e$r
  Uo = res_e$Uo
  Y = res_e$Y
  X = res_e$X
  res_d = mrcivar_data(n=n, p=p, T=T, S=S, SESVI=SESVI, TH=TH, Bo=Bo, Co=Co, Sigmao=Sigmao, Uo=Uo, type=type, X=X, r=r)
  neq = res_e$n
  nvar = res_e$n
  response1 <- array(0, dim = c(neq, nvar, nstep, length(conf) + 1))
  response2 <- array(0, dim = c(neq, nvar, nstep, length(conf) + 1))
  response1[, , , 1] <- IRF1
  response2[, , , 1] <- IRF2
  responseR <- array(0, dim = c(neq, nvar, nstep, runs, S))
  BoColect = array(0, c(dim(Bo), runs))
  UoColect = array(0, c(dim(Uo), runs))
  CoColect = array(0, c(dim(Co), runs))
  YColect = array(0, c(dim(Y), runs))
  Uo_run = array(0, c(T, n, S))
  for (i in 1:runs) {
    for (s in 1:S) Uo_run[, , s] = rnorm_sigma(T, Sigmao[, , s])
    if (length(p) > 1) {
      res_run = mrcivar_data(n = n, p = p, T = T, S = S, SESVI = SESVI, TH = TH, Bo = Bo, Co = Co, Sigmao = Sigmao, Uo = Uo_run, type = type, X=X, r = r)
      res_e_run = mrcivar_estimate(res = res_run)
    }
    IRF1 = irf_from_params(B = res_e_run$Bo[, , , 1], sigma = res_e_run$Sigma[, , 1], nstep = nstep, comb = NA, irf = irf, G = NA)
    IRF2 = irf_from_params(B = res_e_run$Bo[, , , 2], sigma = res_e_run$Sigma[, , 2], nstep = nstep, comb = NA, irf = irf, G = NA)
    responseR[, , , i, 1] <- IRF1
    responseR[, , , i, 2] <- IRF2
    BoColect[, , , , i] <- res_e_run$Bo
    CoColect[, , , i] <- res_e_run$Co
    UoColect[, , , i] <- res_run$Uo
    YColect[, , i] <- res_run$Y
  }
  for (tt in 1:(nstep)) {
    for (i in 1:neq) {
      for (j in 1:nvar) {
        response1[i, j, tt, -1] = stats::quantile(responseR[i, j, tt, , 1], conf)
        response2[i, j, tt, -1] = stats::quantile(responseR[i, j, tt, , 2], conf)
      }
    }
  }
  return(list(response1, response2, BoColect, UoColect, YColect))
}



#'
#' Compute generalized impulse responses for MRCIVAR models
#'
#' Compute generalized impulse response functions (GIRFs) for an estimated
#' MRCIVAR model by comparing average simulated paths with and without an
#' imposed shock across repeated simulation runs.
#'
#' For a shock vector `SHCK`, the GIRF is defined as
#' `mean(Y(SHCK)) - mean(Y(resid))`.
#'
#' See H.H. Pesaran and Y. Shin (1998) Generalized impulse response analysis in linear multivariate 
#' models, Economics Letters, 58(1) p. 17-29.
#' and G. Koop, M. H. Pesaran, and S. M. Potter (1996), Impulse response analysis in nonlinear 
#' multivariate models, Journal of Econometrics, 74 (1996) 119-74.
#'
#' @param res A fitted MRCIVAR object, typically returned by
#'   `mrcivar_estimate()`.
#' @param shock Numeric vector of length `n` defining the impulse.
#' @param R Integer scalar giving the number of simulation runs used to average
#'   over random effects.
#' @param nstep Integer scalar giving the number of response horizons.
#' @param Omega_hist Matrix of initial values used to start the simulation. If
#'   `NA`, the most recent observations are used.
#' @param resid_method Character string specifying how residual draws are
#'   generated. Supported values are `"resid"` and `"parametric"`.
#' @return A three-dimensional array of dimension `(n, n, nstep + 1)`, indexed
#'   by responses, impulses, and horizons.
#'
#' @examples
#' n <- 4
#'
#' Sigma <- 1:(n*n*2)
#' dim(Sigma) <- c(n,n,2)
#' Sigma[,,1] <- diag(n)
#' Sigma[,,2] <- diag(n)
#' p <- matrix(0,2,2)
#' p[,1] <- c(3,3)
#' res_d <- mrcivar_data(n=n, p=p, T=250, S=2, SESVI=1, TH=0, 
#'                          Sigmao=Sigma, type="const", r=2)
#' max(abs(res_d$Y))
#' res_e <- mrcivar_estimate(res=res_d)
#' res_e$Summary
#' Mod(spectral_radius(res_e$B[,,,1]))
#' Mod(spectral_radius(res_e$B[,,,2]))
#'
#' if (!((max(Mod(spectral_radius(res_e$B[,,,1])))>1) | 
#'       (max(Mod(spectral_radius(res_e$B[,,,2])))>1))) {
#'   GIRF <- girf_mrcivar_rm(res=res_e, shock=c(1,1,1,1), R=100, nstep=10, 
#'                            Omega_hist=NA, resid_method="parametric")
#'   GIRF_CB <- girf_mrcivar_rm_cb(res=res_e, shock=c(1,1,1,1), R=100, nstep=10, 
#'                                  Omega_hist=NA, resid_method="parametric", 
#'                                  conf_level=c(0.05,0.95), N=100)
#'   IRF_g <- plot_irf(GIRF_CB)
#' }
#'
#' @export
#' @keywords internal
girf_mrcivar_rm <- function(res, shock, R, nstep, Omega_hist=NA, resid_method) {
  ####  this function generate the impulse response function of MRVAR with migration
  ####
  ####                  	GIRF(shock=SHCK) = mean(Y(resid)) - mean(Y(SHCK))
  ####
  ####
  #### res is the output of mrvar_estimate
  n = res$n
  p = res$p
  S = res$S
  SESVI= res$SESVI; if (is.null(SESVI)) SESVI = NA
  TH= res$TH;    if (is.null(TH))       TH = NA
  Bo= res$Bo
  Co= res$Co
  Sigmao= res$Sigmao
  d= res$d
  type= res$type
  P           = max(p,d);
  X= res$X;  if (!anyNA(X))  X = X[1:(P+nstep+1),]
  Yo= res$Yo; if (is.null(Yo)) Yo = NA
  Uo          = res$Uo
  #res = res$res
  vars_obj = res$vars_obj
  TT          = dim(res$Y)[1]

  IRF = list()
  YR          = list()
  YS          = list()
  residR   <-  list()
  residS   <-  residR

  if (anyNA(Omega_hist)) Omega_hist = res$Y[(dim(res$Y)[1]-P+1):dim(res$Y)[1],,drop=FALSE]
  state <- as.numeric(Omega_hist[P-d+1,SESVI]>TH) + 1

  #R = 400
  #shock       = (1:n)/(1:n)
  DIMresid     = dim(Uo)
  if (length(DIMresid) == 3)  residI = Uo[1:(P+1+nstep),,]*0
  if (length(DIMresid) == 2)  residI = Uo[1:(P+1+nstep),]*0
  shock_mat = Sigmao[,,state]%*%solve(diag(diag(Sigmao[,,state])))%*%diag(shock)

  residI    = array(0,c(P+1+nstep,n,n,DIMresid[3]))

  Yo = Omega_hist
  YR = array(0,c(P+1+nstep,n,n))
  YS <- YR
  MYS <- YS
  MYR <- YS
  GIRF <- array(0,c(n,n,nstep+1))

  for (i in 1:R) {
    if ( resid_method=="resid" ) {
      if (length(DIMresid) == 2)  {
        residI  = Uo[sample_n_out_of_t(P+nstep+1,DIMresid[1]),];
      }
      if (length(DIMresid) == 3)  {
        for (k in 1:n) {
          residI[,,k,]  = Uo[sample_n_out_of_t(P+nstep+1,DIMresid[1]),,];
        }
      }
    }
    if ( resid_method=="parametric" ) {
      if (length(DIMresid) == 2)  {
        residI   = rnorm_sigma(P+nstep+1,Sigmao)
        residI[1:P,]= residI[1:P,]*0
      }
      if (length(DIMresid) == 3)  {
        for (k in 1:n) {
          for (s in 1:S)   residI[,,k,s] = rnorm_sigma(P+nstep+1,Sigmao[,,s])
        }
      }
    }

    residR[[i]] <- residI
    for (s in 1:S) residI[P+1,,,s] <-shock_mat
    residS[[i]] = residI

    for (k in 1:n) {
      YR[,,k] = mrcivar_data(n=n, p=p, T=(P+nstep+1), S=S, SESVI=SESVI, TH=TH, 
                               Bo=Bo, Co=Co, Sigmao=Sigmao, Uo=residR[[i]][,,k,], 
                               type=type, X=X, Yo=Yo, d=d)$Y
      YS[,,k] = mrcivar_data(n=n, p=p, T=(P+nstep+1), S=S, SESVI=SESVI, TH=TH, 
                               Bo=Bo, Co=Co, Sigmao=Sigmao, Uo=residS[[i]][,,k,], 
                               type=type, X=X, Yo=Yo, d=d)$Y
    }

    MYR = MYR + 1/R*YR
    MYS = MYS + 1/R*YS

  }  # end of R loop
  ############## integrating out the disturbances
  for (i in 1:n ) {
    for (j in 1:n) {
      for (k in 1:(nstep+1)) GIRF[i,j,k] = MYS[P+k,i,j]-MYR[P+k,i,j]
    }
  }
  return(GIRF)
}



#'
#' Compute MRCIVAR generalized impulse responses with confidence bands
#'
#' Compute generalized impulse response functions (GIRFs) for an estimated
#' MRCIVAR model and bootstrap confidence bands for a user-specified shock.
#'
#' For a shock vector `SHCK`, the GIRF is defined as
#' `mean(Y(SHCK)) - mean(Y(resid))`.
#'
#' See H.H. Pesaran and Y. Shin (1998) Generalized impulse response analysis in linear multivariate 
#' models, Economics Letters, 58(1) p. 17-29.
#' and G. Koop, M. H. Pesaran, and S. M. Potter (1996), Impulse response analysis in nonlinear 
#' multivariate models, Journal of Econometrics, 74 (1996) 119-74.
#'
#' @param res A fitted MRCIVAR object, typically returned by
#'   `mrcivar_estimate()`.
#' @param shock Numeric vector of length `n` defining the impulse.
#' @param R Integer scalar giving the number of simulation runs used to average
#'   over random effects.
#' @param nstep Integer scalar giving the number of response horizons.
#' @param Omega_hist Matrix of initial values used to start the simulation. If
#'   `NA`, the most recent observations are used.
#' @param resid_method Character string specifying how residual draws are
#'   generated. Supported values are `"resid"` and `"parametric"`.
#' @param conf_level Numeric vector of tail probabilities used to form the
#'   bootstrap confidence interval.
#' @param N Integer scalar giving the number of bootstrap replications.
#' @return A four-dimensional array of dimension `(n, n, nstep + 1,
#'   length(conf_level) + 1)` containing the point estimate and confidence
#'   bounds.
#'
#' @examples
#' n <- 4
#'
#' Sigma <- 1:(n*n*2)
#' dim(Sigma) <- c(n,n,2)
#' Sigma[,,1] <- diag(n)
#' Sigma[,,2] <- diag(n)
#' p <- matrix(0,2,2)
#' p[,1] <- c(3,3)
#' res_d <- mrcivar_data(n=n, p=p, T=250, S=2, SESVI=1, TH=0, 
#'                          Sigmao=Sigma, type="const", r=2)
#' max(abs(res_d$Y))
#' res_e <- mrcivar_estimate(res=res_d)
#' res_e$Summary
#' Mod(spectral_radius(res_e$Bo[,,,1]))
#' Mod(spectral_radius(res_e$Bo[,,,2]))
#'
#' if (! max(Mod(spectral_radius(res_e$Bo[,,,1])), 
#'           Mod(spectral_radius(res_e$Bo[,,,2]))) > 1.0001 ) {
#'   GIRF_CB <- girf_mrcivar_rm_cb(res=res_e, shock=c(1,1,1,1), R=100, nstep=10, 
#'                                  Omega_hist=NA, resid_method="parametric", 
#'                                  conf_level=c(0.05,0.95), N=100)
#'   IRF_g <- plot_irf(GIRF_CB)
#' }
#'
#' @export
girf_mrcivar_rm_cb <- function (res, shock, R, nstep, Omega_hist=NA, resid_method = "parametric", conf_level, N)
{
  n = res$n
  p = res$p
  S = res$S
  SESVI = res$SESVI
  TH = res$TH
  Bo = res$Bo
  Co = res$Co
  Sigmao = res$Sigmao
  d = res$d
  type = res$type
  X = res$X
  d = res$d
  T = dim(res$Y)[1]
  P = max(p, d)
  GIRF = (1:(n * n * (nstep + 1) * N)) * 0
  dim(GIRF) = c(n, n, nstep + 1, N)
  GIRFBd = (1:(n * n * (nstep + 1) * (length(conf_level) + 1))) * 0
  dim(GIRFBd) = c(n, n, nstep + 1, length(conf_level) + 1)
  GIRFBd[, , , 1] = girf_mrcivar_rm(res, shock = shock, R = 2*R, nstep, Omega_hist=Omega_hist, resid_method)
  for (i in 1:N) {
    res_d = mrcivar_data(n = n, p = p, T = T, S = S, SESVI = SESVI, TH = TH, Bo = Bo, Co = Co, Sigmao, type = type, X = X, d = d)
    if (length(colnames(res_d$Y))==0) colnames(res_d$Y) = paste("Y",1:ncol(res_d$Y),sep="")
    RESS = mrcivar_estimate(res_d)
    RF3 = girf_mrcivar_rm(res = RESS, shock = shock, R = R, nstep, Omega_hist=Omega_hist, resid_method)
    GIRF[, , , i] = RF3
  }
  GIRF[,,,1] = GIRFBd[, , , 1]
  for (tt in 1:( nstep + 1)) {
    for (i in 1:n) {
      for (j in 1:n) {
        GIRFBd[i, j, tt, -1] = stats::quantile(GIRF[i, j, tt, ], conf_level)
      }
    }
  }
  return(GIRFBd)
}



#'
#' Compute MRGVAR impulse responses
#'
#' Compute impulse response functions (IRFs) for an estimated MRGVAR model at a
#' specified state configuration.
#'
#' @param res A fitted MRGVAR object, typically returned by `mrgvar_estimate()`.
#' @param state Integer vector of length `n` specifying the state assigned to
#'   each country.
#' @param nstep Integer scalar giving the number of IRF horizons.
#' @param comb Numeric vector defining a combined or concerted-action shock.
#' @param irf Character string specifying the IRF type. Supported values are
#'   `"gen"`, `"chol"`, `"chol1"`, `"gen1"`, `"genN1"`, `"comb1"`, and
#'   `"smat"`.
#' @param G Optional transformation matrix used in permanent-transitory
#'   decompositions.
#' @param smat Optional explicit shock-decomposition matrix.
#' @param sigmaNPDS Optional state-dependent covariance matrix. When `NA`, the
#'   matrix is computed from `res` and `state`.
#' @return A three-dimensional array of dimension `(m * n, m * n, nstep)`,
#'   indexed by responses, impulses, and horizons.
#'
#' @examples
#' \dontrun{
#' ## case of n = 2, m = 2, S = 2     ## m: number of variables, n: number of countries
#' p = rep(1,12); dim(p) = c(2,3,2)
#' p[1,1,2] = 2; p[2,2,2]=2; p[,3,] = 0
#' TH = c(1:2)*0; dim(TH) = c(1,2)
#' res_d <- mrgvar_data(m=2,n=2,p=p,TH=TH,T=100,S=2,SESVI=c(1,3),type="const")
#' max(res_d$Y)
#'
#' ### estimation of the MRGVAR model
#' colnames(res_d$Y) = c("P","Q","Pa","Qa")
#' res_e = mrgvar_estimate(res=res_d)
#' res_e$Summary
#'
#' IRF  = irf_mrgvar(res=res_e,nstep=10,comb=NA,state=c(1,1),irf="gen1")
#' }
#'
#' @export
#' @keywords internal
#'
irf_mrgvar = function(res=res, state=state, nstep=nstep, comb=comb, irf = c("gen", "chol", "chol1", "gen1", "genN1", "comb1", "smat"), G=NA, smat=NA, sigmaNPDS=NA) {
  if (missing(G))
    G = NA
  if (missing(sigmaNPDS))
    sigmaNPDS = NA
  if (missing(smat))
    smat = NA
  neq = dim(res$Go)[1]
  nvar = dim(res$Go)[2]
  m = res$m
  n = res$n
  p = res$p
  if (length(p) > 1)
    pp = max(p[, 1:2, ])
  else
    pp = p
  Bo = res$Bo
  Ao = res$Ao
  W = res$W
  B = bo_ao_ws2_gs(Bo, Ao, W, m, n, pp, state)
  if (anyNA(sigmaNPDS))
    sigma = sigma_npd_select_r(res, state)
  else
    sigma = sigmaNPDS
  response <- array(0, dim = c(neq, nvar, nstep))
  response <- irf_from_params(B, sigma, nstep, comb, irf = irf, G = G, smat = smat)
  return(response)
}



#'
#' Compute generalized impulse responses for MRGVAR models
#'
#' Compute generalized impulse response functions (GIRFs) for an estimated
#' MRGVAR model by comparing average simulated paths with and without an
#' imposed shock across repeated simulation runs.
#'
#' For a shock vector `SHCK`, the GIRF is defined as
#' `mean(Y(SHCK)) - mean(Y(resid))`.
#'
#' See H.H. Pesaran and Y. Shin (1998) Generalized impulse response analysis in linear multivariate 
#' models, Economics Letters, 58(1) p. 17-29.
#'
#' @param res A fitted MRGVAR object, typically returned by `mrgvar_estimate()`.
#' @param shock Numeric vector of length `m * n` defining the impulse.
#' @param R Integer scalar giving the number of simulation runs used to average
#'   over random effects.
#' @param nstep Integer scalar giving the number of response horizons.
#' @param Omega_hist Matrix of initial values used to start the simulation. If
#'   `NA`, the most recent observations are used; if `0`, zero initial values
#'   are used.
#' @param resid_method Character string specifying how residual draws are
#'   generated. Supported values are `"resid"` and `"parametric"`.
#' @return A list with three elements: the GIRF array of dimension `(m * n,
#'   m * n, nstep + 1)`, the shocked simulated paths, and the baseline simulated
#'   paths.
#'
#' @examples
#' ## Minimal, quick example (safe to run in checks)
#' ## n: number of countries, m: number of variables, S: simulation draws
#' \dontrun{
#' p <- rep(1, 12); dim(p) <- c(2, 3, 2)
#' p[1, 1, 2] <- 2; p[2, 2, 2] <- 2; p[, 3, ] <- 0
#' TH <- c(1:2) * 0; dim(TH) <- c(1, 2)
#' res_d <- mrgvar_data(m = 2, n = 2, p = p, TH = TH, T = 50, S = 2,
#'                      SESVI = c(1, 3), type = "const")
#' max(res_d$Y)
#'
#' \donttest{
#'   ## Full workflow example (can be slow / sensitive to numerical issues)
#'   colnames(res_d$Y) <- c("P", "Q", "Pa", "Qa")
#'   res_e <- mrgvar_estimate(res = res_d)
#'   res_e$Summary
#'
#'   GIRF <- girf_mrgvar_rm(res = res_e, shock = c(1, 1, 1, 1), R = 100,
#'                          nstep = 10, Omega_hist = NA, resid_method = "parametric")
#'   GIRF_CB <- girf_mrgvar_rm_cb(res = res_e, shock = c(1, 1, 1, 1), R = 100,
#'                                nstep = 10, Omega_hist = NA,
#'                                resid_method = "parametric",
#'                                conf = c(0.05, 0.95), N = 10)
#'   IRF_g <- plot_irf(GIRF_CB, Names = c("P", "Q", "Pa", "Qa"))
#' }
#' }
#'
#' @export
#' @keywords internal
girf_mrgvar_rm <- function(res, shock, R, nstep, Omega_hist, resid_method) {
  ####  this function generate the impulse response function of MRVAR with regime migration
  ####
  ####                  GIRF(shock=SHCK) = mean(Y(resid)) - mean(Y(SHCK))
  ####
  ####
  #### RES is the output of MRVAREST1
  n 		  = res$n
  m 		  = res$m
  p 		  = res$p
  d		    = res$d
  S 		  = res$S
  SESVI	  = res$SESVI
  TH		  = res$TH
  Go      = res$Go
  Bo		  = res$Bo
  Ao      = res$Ao
  Co		  = res$Co
  Sigmao  = res$Sigmao
  W       = res$W
  type	  = res$type
  SV      = res$SV
  P       = max(d,p)
  X 		  = res$X; if (!anyNA(X)) X = X[1:(P+nstep+1),];
  Yo		  = res$Yo
  Uo      = res$Uo
  TT      = dim(res$Y)[1]
  d       = res$d
  IRF 	  = list()
  YR      = list()
  YS      = list()
  residR  <-  list()
  residS  <-  residR

  if (anyNA(Omega_hist)) {
    Omega_hist = res$Y[(dim(res$Y)[1]-P+1):dim(res$Y)[1],,drop=FALSE]
  }  else  {
    if (Omega_hist==0) Omega_hist = res$Y[(dim(res$Y)[1]-P+1):dim(res$Y)[1],,drop=FALSE]*0
  }

  state <- as.numeric(Omega_hist[P-d+1,SESVI]>TH) + 1

  #R 		= 400
  #shock       = (1:n)/(1:n)

  DIMresid    = dim(Uo)
  if (length(DIMresid) == 3)  residI = Uo[1:(P+1+nstep),,]*0
  if (length(DIMresid) == 2)  residI = Uo[1:(P+1+nstep),]*0
  shock_mat = matrix(0,m*n,m*n)
  Sigma_s = sigma_npd(res,state)

  shock_mat = Sigma_s%*%solve(diag(diag(Sigma_s)))%*%diag(shock)

  residI    = array(0,c(P+1+nstep,m*n,m*n,DIMresid[3]))

  residI    = array(0,c(P+1+nstep,m*n,m*n,DIMresid[3]))

  Yo = Omega_hist
  YR = array(0,c(P+1+nstep,m*n,m*n))
  YS <- YR
  MYS <- YS
  MYR <- YS
  GIRF <- array(0,c(m*n,m*n,nstep+1))



  for (i in 1:R) {
    if ( resid_method=="resid" ) {

      if (length(DIMresid) == 3)  {
        for (k in 1:(m*n)) {
          residI[,,k,]  = Uo[sample_n_out_of_t(P+nstep+1,DIMresid[1]),,];
        }
      }
    }
    if ( resid_method=="parametric" ) {

      if (length(DIMresid) == 3)  {
        for (k in 1:(m*n)) {
          for (s in 1:S)   residI[,,k,s] = rnorm_sigma(P+nstep+1,Sigmao[,,s])
        }
      }
    }
    #residI[P+1,,,] = 0
    residR[[i]] <- residI
    for (s in 1:S) {residI[P+1,,,s] <-shock_mat}    # such that residI[P+1,,k,] corresponds to the k-th column shock in shock_mat for both regimes (budui dan ok)
    residS[[i]] = residI

    for (k in 1:DIMresid[2]) {
      YR[,,k] = mrgvar_data(m=m,n=n,p=p,T=(P+nstep+1),S=S,W=W,SESVI=SESVI,TH=TH,Go=Go,Ao=Ao,Bo=Bo,Sigmao=Sigmao,Uo=residR[[i]][,,k,],SV=SV,type=type,Co=Co,X=X,Yo=Yo,d=d)$Y
      YS[,,k] = mrgvar_data(m=m,n=n,p=p,T=(P+nstep+1),S=S,W=W,SESVI=SESVI,TH=TH,Go=Go,Ao=Ao,Bo=Bo,Sigmao=Sigmao,Uo=residS[[i]][,,k,],SV=SV,type=type,Co=Co,X=X,Yo=Yo,d=d)$Y
      ## to delete YS[[i]] = mrgvar_data(m=m,n=n,p=p,T=(P+nstep+1),S=S,W=W,SESVI=SESVI,TH=TH,Go=Go,Ao=Ao,Bo=Bo,Sigmao=Sigmao,Uo=residS[[i]],SV=SV,type=type,Co=Co,X=X,Yo=Yo*0,d=d)
    }

    MYR = MYR + 1/R*YR
    MYS = MYS + 1/R*YS

  }  # end of R loop
  ############## integrating out the disturbances
  for (i in 1:(m*n) ) {
    for (j in 1:(m*n)) {
      for (k in 1:(nstep+1)) GIRF[i,j,k] = MYS[P+k,i,j]-MYR[P+k,i,j]
    }
  }
  return(list(GIRF,MYS[(P+1):(P+1+nstep),,],MYR[(P+1):(P+1+nstep),,]))
}



#'
#' Compute MRGVAR generalized impulse responses with confidence bands
#'
#' Compute generalized impulse response functions (GIRFs) for an estimated
#' MRGVAR model and bootstrap confidence bands for a user-specified shock.
#'
#' For a shock vector `SHCK`, the GIRF is defined as
#' `mean(Y(SHCK)) - mean(Y(resid))`.
#'
#' See H.H. Pesaran and Y. Shin (1998) Generalized impulse response analysis in linear multivariate 
#' models, Economics Letters, 58(1) p. 17-29.
#'
#' @param res A fitted MRGVAR object, typically returned by `mrgvar_estimate()`.
#' @param shock Numeric vector of length `m * n` defining the impulse.
#' @param R Integer scalar giving the number of simulation runs used to average
#'   over random effects.
#' @param nstep Integer scalar giving the number of response horizons.
#' @param Omega_hist Matrix of initial values used to start the simulation. If
#'   `NA`, the most recent observations are used.
#' @param resid_method Character string specifying how residual draws are
#'   generated. Supported values are `"resid"` and `"parametric"`.
#' @param conf Numeric vector of tail probabilities used to form the bootstrap
#'   confidence interval.
#' @param N Integer scalar giving the number of bootstrap replications.
#' @return A four-dimensional array of dimension `(m * n, m * n, nstep + 1,
#'   length(conf) + 1)` containing the point estimate and confidence bounds.
#'
#' @examples
#' ## case of n = 2, m = 2, S = 2     ## m: number of variables, n: number of countries
#' \dontrun{
#' p = rep(1, 12); dim(p) = c(2, 3, 2)
#' p[1, 1, 2] = 2; p[2, 2, 2] = 2; p[, 3, ] = 0
#' TH = c(1:2) * 0; dim(TH) = c(1, 2)
#' res_d <- mrgvar_data(m = 2, n = 2, p = p, TH = TH, T = 100, S = 2, 
#'                       SESVI = c(1, 3), type = "const")
#' max(res_d$Y)
#'
#' ### estimation of the MRGVAR model
#' colnames(res_d$Y) = c("P", "Q", "Pa", "Qa")
#' res_e = mrgvar_estimate(res = res_d)
#' res_e$Summary
#'
#' Mod(spectral_radius(res_e$Go[, , , 1]))
#' Mod(spectral_radius(res_e$Go[, , , 2]))
#'
#' GIRF = girf_mrgvar_rm(res = res_e, shock = c(1, 1, 1, 1), R = 100, 
#'                        nstep = 10, Omega_hist = NA, resid_method = 'parametric')
#' GIRF_CB = girf_mrgvar_rm_cb(res = res_e, shock = c(1, 1, 1, 1), R = 100, 
#'                              nstep = 10, Omega_hist = NA, 
#'                              resid_method = 'parametric', conf = c(0.05, 0.95), N = 10)
#' GIRF_g = plot_irf(GIRF_CB, Names = c("P", "Q", "Pa", "Qa"))
#' }
#'
#' @export
girf_mrgvar_rm_cb <- function(res, shock, R, nstep, Omega_hist = NA, 
                resid_method = "parametric", conf, N) {
  n = res$n
  m = res$m
  p = res$p
  S = res$S
  SESVI = res$SESVI
  TH = res$TH
  Go = res$Go
  Bo = res$Bo
  Ao = res$Ao
  Co = res$Co
  Sigmao = res$Sigmao
  W = res$W
  type = res$type
  SV = res$SV
  X = res$X
  Yo = res$Yo
  d = res$d
  Uo = res$Uo
  T = dim(res$Y)[1]
  P = max(d, p)
  
  GIRF = (1:(m * n * n * m * (nstep + 1) * N)) * 0
  dim(GIRF) = c(m * n, m * n, nstep + 1, N)
  
  GIRFBd = (1:(m * n * n * m * (nstep + 1) * (length(conf) + 1))) * 0
  dim(GIRFBd) = c(m * n, m * n, nstep + 1, length(conf) + 1)
  
  GIRFBd[, , , 1] = girf_mrgvar_rm(res, shock, R = 2 * R, nstep, Omega_hist, resid_method)[[1]]
  
  for (i in 1:N) {
  res_run = mrgvar_data_r(res)
  if (length(colnames(res_run$Y)) == 0) colnames(res_run$Y) = paste("res_runY", 1:ncol(res_run$Y), sep = "")
  res_erun = mrgvar_estimate(res_run)
  RF3 = girf_mrgvar_rm(res = res_erun, shock, R, nstep, Omega_hist, resid_method)[[1]]
  GIRF[, , , i] = RF3
  }
  
  for (tt in 1:(nstep + 1)) {
  for (i in 1:(n * m)) {
    for (j in 1:(n * m)) {
    GIRFBd[i, j, tt, -1] = stats::quantile(GIRF[i, j, tt, ], conf)
    }
  }
  }
  
  return(GIRFBd)
}



#'
#' Compute regime-specific MRGVAR impulse responses with confidence bands
#'
#' Compute regime-specific impulse response functions for an estimated MRGVAR
#' model and bootstrap confidence bands for a selected state configuration.
#'
#' @param res A fitted MRGVAR object, typically returned by `mrgvar_estimate()`.
#' @param state Integer vector of length `n` specifying the state assigned to
#'   each country.
#' @param nstep Integer scalar giving the number of IRF horizons.
#' @param comb Numeric vector defining a combined or concerted-action shock.
#' @param irf Character string specifying the IRF type. Supported values are
#'   `"gen"`, `"chol"`, `"chol1"`, `"gen1"`, and `"comb1"`.
#' @param G Optional transformation matrix used in permanent-transitory
#'   decompositions.
#' @param smat Optional explicit shock-decomposition matrix.
#' @param sigmaNPDS Optional state-dependent covariance matrix. When `NA`, the
#'   matrix is computed from `res` and `state`.
#' @param runs Integer scalar giving the number of bootstrap replications.
#' @param conf Numeric vector of tail probabilities used to form the bootstrap
#'   confidence interval.
#' @param NT Integer scalar giving the number of simulated IRF scenarios.
#' @return A list of bootstrap results. Its first element is a
#'   four-dimensional array containing the point estimate and confidence bounds,
#'   indexed by responses, impulses, horizons, and interval component.
#' @examples
#' \dontrun{
#' ## case of n = 2, m = 2, S = 2     ## m: number of variables, n: number of countries
#' p = rep(1,12); dim(p) = c(2,3,2)
#' p[1,1,2] = 2; p[2,2,2]=2; p[,3,] = 0
#' TH = c(1:2)*0; dim(TH) = c(1,2)
#' res_d <- mrgvar_data(m=2,n=2,p=p,TH=TH,T=100,S=2,SESVI=c(1,3),type="const")
#' max(res_d$Y)
#'
#' ### estimation of the MRGVAR model
#' colnames(res_d$Y) = c("P","Q","Pa","Qa")
#' res_e = mrgvar_estimate(res=res_d)
#' res_e$Summary
#'
#' IRF_CB  = irf_mrgvar_cb(res=res_e,nstep=10,comb=NA,state=c(1,1),irf="gen1",runs=20,
#' conf=c(0.05,0.95))
#' IRF_g = plot_irf(IRF_CB[[1]],Names=c("P","Q","Pa","Qa"))    #IRF
#' #IRF_g = plot_irf(IRF_CB[[2]])   # accumulated IRF
#' }
#'
#' @export
irf_mrgvar_cb = function (res, state = c(2, 1), nstep, comb, irf = c("gen", "chol", "chol1", "gen1", "comb1"), G=NA, smat=NA, sigmaNPDS=NA, runs = 200, conf = c(0.05, 0.95), NT = 1) {
  m = res$m
  n = res$n
  p = res$p
  if (length(p) > 1)
    pp = max(p[, 1:2, ])
  else pp = p
  T = dim(res$Y)[1] * NT
  W = res$W
  S = res$S
  SV = res$SV
  SESVI = res$SESVI
  TH = res$TH
  Ao = res$Ao
  Bo = res$Bo
  Co = res$Co
  Go = res$Go
  GoColect = array(0, c(dim(Go), runs))
  BoColect = array(0, c(dim(Bo), runs))
  AoColect = array(0, c(dim(Ao), runs))
  UoColect = array(0, c(T, m * n, S, runs))
  YColect = array(0, c(T, m * n, runs))
  type = res$type
  X = res$X
  mu = res$mu
  B = bo_ao_ws2_gs(Bo, Ao, W, m, n, pp, state)
  neq = dim(B)[1]
  nvar = dim(B)[2]
  sigma = res$Sigmao
  response <- array(0, dim = c(neq, nvar, nstep, length(conf) + 1))
  accresponse <- response
  sigmaNPDS = sigma_npd(res, state)
  response[, , , 1] <- irf_mrgvar(res=res, nstep=nstep, comb=comb, state=state, irf=irf)
  accresponse[, , , 1] <- response[, , , 1]
  for (tt in 2:nstep) {  accresponse[, ,tt, 1] = accresponse[, ,tt-1, 1] + response[, ,tt, 1] }

  responseR <- array(0, dim = c(neq, nvar, nstep, runs))
  accresponseR <- responseR
  Uo_run = array(0, c(T, n * m, S))
  for (i in 1:runs) {
    for (s in 1:S) Uo_run[, , s] = rnorm_sigma(T, res$Sigmao[,, s])
    if (length(p) > 1) {
      res_run = mrgvar_data_r(res)
      if (length(colnames(res_run$Y))==0) colnames(res_run$Y) = paste("res_runY",1:ncol(res_run$Y),sep="")
      res_e   = mrgvar_estimate(res_run)
    }

    responseR[, , , i] <- irf_mrgvar(res=res_e,  state=state,nstep=nstep, comb=comb, irf=irf, G=G, smat=smat, sigmaNPDS=sigmaNPDS)
    accresponseR[, , , i] <-  responseR[, , , i]
    for (tt in 2:nstep) {  accresponseR[, ,tt, i] = accresponseR[, ,tt-1, i] + responseR[, ,tt, i] }
    GoColect[, , , , i] <- res_e$Go
    BoColect[, , , , , i] <- res_e$Bo
    AoColect[, , , , , i] <- res_e$Ao
    #UoColect[, , , i] <- res_run$Uo
    #YColect[, , i] <- res_run$Y
  }
  responseR[, , , 1]    = response[, , , 1]
  accresponseR[, , , 1] = accresponse[, , , 1]

  for (tt in 1:(nstep)) {
    for (i in 1:neq) {
      for (j in 1:nvar) {
        response[i, j, tt, -1]    = stats::quantile(responseR[i, j, tt, ], conf)
        accresponse[i, j, tt, -1] = stats::quantile(accresponseR[i, j, tt, ], conf)
      }
    }
  }
  return(list(response, accresponse, GoColect, BoColect, AoColect, UoColect, YColect, responseR))
}



#'
#' Calculate Accumulated Impulse Response Functions
#'
#' This function calculates the cumulative impulse response functions from a given set of impulse response functions.
#' It sums the impulse responses over time to provide a cumulative effect of the shocks.
#'
#' @param IRF An impulse response function
#'
#' @return The cumulative impulse response function
#' @examples
#' # Example usage of accirf_conf_r
#' # Assuming IRF is a predefined impulse response function arrays
#' p = matrix(c(2,1,0,0),2,2)
#' res_d = mrvar_data(n=2,p=p,T=300,S=2,SESVI=1)
#' max(abs(res_d$Y))
#' res_e  = mrvar_estimate(res_d)
#' res_e$Summary
#' 
#' IRF <- irf_mrvar_nm(res_e,nstep=10,comb=NA,irf="gen")
#' cumulative_response <- accirf_conf_r(IRF)
#' @export
#'
#' @keywords internal
#'
accirf_conf_r <- function(IRF) {
  ACCirf = IRF
  dm = dim(IRF)
  for (t in 2:dm[3]) {
    ACCirf[,,t,] = ACCirf[,,t-1,] + IRF[,,t,]
  }
  return(ACCirf)
}



#'
#' Calculate Global Impulse Response Functions with Confidence Bands
#'
#' This function calculates global or regional responses from a set of bootstrapped impulse response functions 
#' and a weighting matrix for the aggregation of the global responses. It returns both the global impulse response 
#' functions and their accumulated versions, along with confidence intervals.
#'
#' @param IRF_CB an output of irf_mrgvar_cb
#' @param comb_all a weighting matrix for the aggregation of the global responses
#'
#' @return a list containing the global impulse response functions and the accumulated global impulse response functions.
#' @examples
#' # Example usage of irf_global_response_cb
#' # Assuming IRF_CB is the output from irf_mrgvar_cb and comb_all is a predefined weighting matrix
#' # Define a simple "comb_all" (weighting matrix) for the global aggregation
#' # Equal-weight "comb_all" across 2 countries (two identical columns)
#' \dontrun{
#' comb_all = matrix(c(0.5, 0.5, 0.5, 0.5), nrow = 2, ncol = 2)
#' p = matrix(c(2,1,0,0),2,2)
#' res_d = mrvar_data(n=2,p=p,T=300,S=2,SESVI=1)
#' max(abs(res_d$Y))
#' res_e  = mrvar_estimate(res_d)
#' res_e$Summary
#' 
#' IRF_CB <- irf_mrvar_nm_cb(res_e,nstep=10,comb=NA,irf="gen",runs=200,conf=c(0.05,0.90))
#' result <- irf_global_response_cb(IRF_CB, comb_all)
#' }
#' @export
#'
irf_global_response_cb <- function(IRF_CB, comb_all) {
  
  bootarray <- IRF_CB[[8]]
  DIM <- dim(bootarray)
  glresp <- dim(comb_all)[2]
  nN <- DIM[1]
  nstep <- DIM[3]
  nrun <- DIM[4]
  globalbootarray <- array(0, dim = c(glresp, nN, nstep, nrun))
  
  for (m in 1:glresp) {
  for (j in 1:(nN)) {
    for (k in 1:nstep) {
    for (q in 1:nrun) {
      globalbootarray[m, j, k, q] = sum(bootarray[, j, k, q] * comb_all[, m])
    }
    }
  }
  }
  
  globalbootconf = c(1:(3 * glresp * nN * nstep)) * 0
  dim(globalbootconf) = c(glresp, nN, nstep, 3)
  globalbootconf[,,,1] = globalbootarray[,,,1]
  
  for (i in 1:glresp) {
  for (j in 1:(nN)) {
    for (k in 1:nstep) {
    globalbootconf[i, j, k, 2:3] = stats::quantile(globalbootarray[i, j, k, ], c(.05, .95))
    }
  }
  }
  
  ACCbootconf3N = accirf_conf_r(globalbootconf)
  return(list(globalbootconf, ACCbootconf3N))
}



#' Calculate Generalized Impulse Response Functions for MRVAR Models
#'
#' This function calculates the generalized impulse response functions (GIRF) of an estimated 
#' MRVAR(n,p,S) model for a given shock vector. It computes the difference between mean responses 
#' with and without the shock, integrating out random effects across multiple simulation runs.
#'
#' ### GIRF(shock=SHCK) = mean(Y(resid)) - mean(Y(SHCK))
#'
#' See H.H. Pesaran and Y. Shin (1998) Generalized impulse response analysis in linear multivariate 
#' models, Economics Letters, 58(1) p. 17-29, and G. Koop, M. H. Pesaran, and S. M. Potter (1996), 
#' Impulse response analysis in nonlinear multivariate models, Journal of Econometrics, 74 (1996) 119-74.
#'
#' @param  RES   : an MRVAR object that is an output of MRVARest.
#' @param  shock : an n vector containing the shocks as impulse.
#' @param  R     : the number of runs to integrate out the random effects in order to obtain the means.
#' @param  nstep : the length of the responses.
#' @param  Omega_hist : a (P x n) matrix of initial values, from which the impulse response functions start. 
#'                      For Omega_hist=NA, the impulse response functions will start from the most recent observations.
#' @param  resid_method : resid_method = c("resid", "parametric"), it generates the random residuals from 
#'                        residuals bootstrap or parametric bootstrap.
#' @return an (n x n x nstep+1) matrix of impulse response functions. The rows represent responses and the columns represent impulses.
#' @examples
#' p = matrix(c(2,1,0,0),2,2)
#' res_d = mrvar_data(n=2,p=p,T=300,S=2,SESVI=1,type="none")
#' max(res_d$Y)
#' colnames(res_d$Y) = c("R","P")
#' res_e = mrvar_estimate(res=res_d)
#' RF3 = girf_mrvar_rm(RES=res_e,shock=c(1,1),R = 100,nstep=20,Omega_hist=NA,resid_method="parametric")
#' RF4 = girf_mrvar_rm_cb(RES=res_e, shock=c(1,1), R=100, nstep=20, Omega_hist=NA,
#' resid_method = "parametric", conf_level=c(0.05,0.95), N=100)
#' IRF_list <- plot_irf(RF4)
#' @export
#' @keywords internal
girf_mrvar_rm <- function(RES, shock, R, nstep, Omega_hist = NA, resid_method) {
  ####  this function generate the impulse response function of MRVAR with migration
  ####
  ####                  	GIRF(shock=SHCK) = mean(Y(resid)) - mean(Y(SHCK))
  ####
  #### RES is the output of mrvar_estimate
  n = RES$n
  p = RES$p
  S = RES$S
  SESVI = RES$SESVI; if (is.null(SESVI)) SESVI = NA
  TH = RES$TH; if (is.null(TH)) TH = NA
  Bo = RES$Bo
  Co = RES$Co
  Sigmao = RES$Sigmao
  d = RES$d
  type = RES$type
  P = max(p, d)
  X = RES$X; if (!anyNA(X)) X = X[1:(P + nstep + 1), ]
  Yo = RES$Yo; if (is.null(Yo)) Yo = NA
  Uo = RES$Uo
  vars_obj = RES$vars_obj
  TT = dim(RES$Y)[1]

  IRF = list()
  YR = list()
  YS = list()
  residR = list()
  residS = residR

  if (anyNA(Omega_hist)) Omega_hist = RES$Y[(dim(RES$Y)[1] - P + 1):dim(RES$Y)[1], , drop = FALSE]
  state <- as.numeric(Omega_hist[P - d + 1, SESVI] > TH) + 1

  DIMresid = dim(Uo)
  if (length(DIMresid) == 3) residI = Uo[1:(P + 1 + nstep), , ] * 0
  if (length(DIMresid) == 2) residI = Uo[1:(P + 1 + nstep), ] * 0
  shock_mat = Sigmao[, , state] %*% solve(diag(diag(Sigmao[, , state]))) %*% diag(shock)

  residI = array(0, c(P + 1 + nstep, n, n, DIMresid[3]))

  Yo = Omega_hist
  YR = array(0, c(P + 1 + nstep, n, n))
  YS = YR
  MYS = YS
  MYR = YS
  GIRF = array(0, c(n, n, nstep + 1))

  for (i in 1:R) {
    if (resid_method == "resid") {
      if (length(DIMresid) == 2) {
        residI = Uo[sample_n_out_of_t(P + nstep + 1, DIMresid[1]), ]
      }
      if (length(DIMresid) == 3) {
        for (k in 1:n) {
          residI[, , k, ] = Uo[sample_n_out_of_t(P + nstep + 1, DIMresid[1]), , ]
        }
      }
    }
    if (resid_method == "parametric") {
      if (length(DIMresid) == 2) {
        residI = rnorm_sigma(P + nstep + 1, Sigmao)
        residI[1:P, ] = residI[1:P, ] * 0
      }
      if (length(DIMresid) == 3) {
        for (k in 1:n) {
          for (s in 1:S) residI[, , k, s] = rnorm_sigma(P + nstep + 1, Sigmao[, , s])
        }
      }
    }

    residR[[i]] <- residI
    residI[P + 1, , , state] <- shock_mat
    residS[[i]] = residI

    for (k in 1:n) {
      YR[, , k] = mrvar_data(n = n, p = p, T = (P + nstep + 1), S = S, SESVI = SESVI, TH = TH, Bo = Bo, Co = Co, Sigmao = Sigmao, Uo = residR[[i]][,, k, ], type = type, X = X, Yo = Yo, d = d)$Y
      YS[, , k] = mrvar_data(n = n, p = p, T = (P + nstep + 1), S = S, SESVI = SESVI, TH = TH, Bo = Bo, Co = Co, Sigmao = Sigmao, Uo = residS[[i]][,, k, ], type = type, X = X, Yo = Yo, d = d)$Y
    }

    MYR = MYR + 1/R * YR
    MYS = MYS + 1/R * YS
  }  # end of R loop

  ############## integrating out the disturbances
  for (i in 1:n) {
    for (j in 1:n) {
      for (k in 1:(nstep + 1)) GIRF[i, j, k] = MYS[P + k, i, j] - MYR[P + k, i, j]
    }
  }
  return(GIRF)
}



#'
#' Calculate Generalized Impulse Response Functions with Bootstrapped Confidence Intervals for MRVAR Models
#'
#' This function calculates the generalized impulse response functions (GIRF) of an estimated MRVAR(n,p,S) 
#' for a given shock vector. It also provides bootstrapped confidence intervals for the impulse response functions.
#'
#' ### GIRF(shock=SHCK) = mean(Y(resid)) - mean(Y(SHCK))
#'
#' See H.H. Pesaran and Y. Shin (1998) Generalized impulse response analysis in linear multivariate models, 
#' Economics Letters, 58(1) p. 17-29, and G. Koop, M. H. Pesaran, and S. M. Potter (1996), 
#' Impulse response analysis in nonlinear multivariate models, Journal of Econometrics, 74 (1996) 119-74.
#'
#' @param  RES        : an estimated MRVAR object.
#' @param  shock      : an n-vector containing the shocks as impulse.
#' @param  R         : number of runs to integrate out the random effects in order to obtain the means (see equation above).
#' @param  nstep     : length of the impulse response function.
#' @param  Omega_hist : a (P x n) matrix of initial values, from which the impulse response functions start. 
#'                      Omega_hist determines from which regime the impulse response functions start.
#' @param  resid_method : resid_method = c("resid", "parametric"), it generates the random residuals from 
#'                       residuals bootstrap or parametric bootstrap.
#' @param  conf_level : a vector containing the levels of confidence.
#' @param  N         : the number of bootstrap runs in containing the bootstrapped confidence intervals.
#' @return an (n, n, nstep+1, 3) array containing the impulse response functions with lower and upper confidence bands. 
#'         The rows represent responses, and the columns represent impulses.
#' @examples
#' p = matrix(c(2,1,0,0),2,2)
#' res_d = mrvar_data(n=2,p=p,T=300,S=2,SESVI=1,type="none")
#' max(res_d$Y)
#' colnames(res_d$Y) = c("R","P")
#' res_e = mrvar_estimate(res=res_d)
#' RF3 = girf_mrvar_rm(RES=res_e,shock=c(1,1),R = 200,nstep=20,Omega_hist=NA,resid_method="parametric")
#' RF4 = girf_mrvar_rm_cb(RES=res_e, shock=c(1,1), R=200, nstep=20, Omega_hist=NA,
#'                         resid_method="parametric", conf_level=c(0.05,0.95), N=100)
#' IRF_list <- plot_irf(RF4)
#' @export
girf_mrvar_rm_cb <- function(RES, shock, R, nstep, Omega_hist = NA, resid_method = "parametric", conf_level, N) {
  n = RES$n
  p = RES$p
  S = RES$S
  SESVI = RES$SESVI
  TH = RES$TH
  Bo = RES$Bo
  Co = RES$Co
  Sigmao = RES$Sigmao
  d = RES$d
  type = RES$type
  X = RES$X
  T = dim(RES$Y)[1]
  P = max(p, d)
  
  GIRF = (1:(n * n * (nstep + 1) * N)) * 0
  dim(GIRF) = c(n, n, nstep + 1, N)
  
  GIRFBd = (1:(n * n * (nstep + 1) * (length(conf_level) + 1))) * 0
  dim(GIRFBd) = c(n, n, nstep + 1, length(conf_level) + 1)
  
  GIRFBd[, , , 1] = girf_mrvar_rm(RES, shock = shock, R = 2 * R, nstep, Omega_hist = Omega_hist, resid_method)
  
  for (i in 1:N) {
    res_d = mrvar_data(n = n, p = p, T = T, S = S, SESVI = SESVI, TH = TH, Bo = Bo, Co = Co, Sigmao, type = type, X = X, d = d)
    if (length(colnames(res_d$Y)) == 0) colnames(res_d$Y) = paste("Y", 1:ncol(res_d$Y), sep = "")
    RESS = mrvar_estimate(res_d)
    RF3 = girf_mrvar_rm(RES = RESS, shock = shock, R = R, nstep, Omega_hist = Omega_hist, resid_method)
    GIRF[, , , i] = RF3
  }
  
  GIRF[,,,1] = GIRFBd[, , , 1]
  
  for (tt in 1:(nstep + 1)) {
    for (i in 1:n) {
      for (j in 1:n) {
        GIRFBd[i, j, tt, -1] = stats::quantile(GIRF[i, j, tt, ], conf_level)
      }
    }
  }
  
  return(GIRFBd)
}



#'
#' Calculate Regime Specific Impulse Response Functions for MRVAR Models
#'
#' This function calculates the regime specific impulse response functions of an estimated MRVAR(n,p,S),
#' using the Bo\[,,,s\] and Sigma\[,,s\] matrices of the estimated MRVAR(n,p,S).
#'
#' @param RESS an output of mrvar_estimate
#' @param nstep the length of impulse response function
#' @param comb a vector specifying the weights used in GVAR models. For MRVAR its value is NA.
#' @param irf types of the impulse response functions. irf=c("gen","chol","chol1","gen1","comb1"),
#'            gen for generalized IRF with one standard deviation shocks,
#'            gen1 for generalized IRF with one unit impulse,
#'            chol for IRF with Cholezky decomposition of the covariance matrix,
#'            chol1 for Cholezky decomposition with one unit impulse,
#'            comb1 for concerted action with one unit impulse in GVAR.
#' @return an (n,n,nstep,2) array of IRF with columns representing the impulse and rows the responses.
#' @examples
#' p = matrix(c(2,1,0,0),2,2)
#' res_d = mrvar_data(n=2,p=p,T=300,S=2,SESVI=1)
#' max(abs(res_d$Y))
#' res_e  = mrvar_estimate(res_d)
#' res_e$Summary
#'
#' IRF    = irf_mrvar_nm(res_e,nstep=10,comb=NA,irf="gen")
#' IRF_CB = irf_mrvar_nm_cb(res_e,nstep=10,comb=NA,irf="gen",runs=200,conf=c(0.05,0.90))
#' IRF_list1 <- plot_irf(IRF_CB[,,,,1])
#' IRF_list2 <- plot_irf(IRF_CB[,,,,2])
#'
#' @export
#' @keywords internal
#'
irf_mrvar_nm <- function(RESS, nstep, comb, irf = c("gen", "chol", "chol1", "gen1", "comb1")) {
  p = RESS$p
  Bo = RESS$Bo
  Sigmao = RESS$Sigmao
  neq = dim(Bo)[1]
  nvar = dim(Bo)[2]
  S = dim(Bo)[4]
  response <- array(0, dim = c(neq, nvar, nstep, S))
  BBo = list()
  
  for (s in 1:S) {
    BBo[[s]] = Bo[, , 1:p[s, 1], s]
    if (length(dim(BBo[[s]])) < 3)
      dim(BBo[[s]]) = c(dim(BBo[[s]]), 1)
  }
  
  for (s in 1:S) 
    response[, , , s] <- irf_from_params(B = BBo[[s]], sigma = Sigmao[, , s], nstep, comb, irf = irf)
  
  return(response)
}



#'
#' Calculate Regime Specific Impulse Response Functions with Confidence Bands for MRVAR Models
#'
#' This function calculates the regime specific impulse response functions of an estimated MRVAR(n,p,S),
#' using the Bo\[,,,s\] and Sigma\[,,s\] matrices of the estimated MRVAR. It also provides bootstrapped 
#' confidence intervals for the impulse response functions.
#'
#' @param RESS an output of MRVARest.
#' @param nstep the length of impulse response function
#' @param comb a vector specifying the concerted action in policy-simulation impulse response function
#' @param irf types of the impulse response functions. irf=c("gen","chol","chol1","gen1","comb1"), 
#'            gen for generalized IRF with one standard deviation shocks, 
#'            gen1 for generalized IRF with one unit impulse, 
#'            chol for IRF with Cholezky decomposition of the covariance matrix, 
#'            chol1 for Cholezky decomposition with one unit impulse, 
#'            comb1 for concerted action with one unit impulse in GVAR.
#' @param runs number of simulation runs
#' @param conf a two components vector containing the tail probabilities of the bootstrap confidence interval.
#' @return an (n,n,nstep,3,2) array containing the IRF of the two regimes. The IRF columns represent the impulse and the rows the responses.
#' @examples
#' p = matrix(c(2,1,0,0),2,2)
#' res_d = mrvar_data(n=2,p=p,T=300,S=2,SESVI=1)
#' max(abs(res_d$Y))
#' res_e  = mrvar_estimate(res_d)
#' res_e$Summary
#'
#' IRF    = irf_mrvar_nm(res_e,nstep=10,comb=NA,irf="gen")
#' IRF_CB = irf_mrvar_nm_cb(res_e,nstep=10,comb=NA,irf="gen",runs=200,conf=c(0.05,0.90))
#' IRF_list1 <- plot_irf(IRF_CB[,,,,1])
#' IRF_list2 <- plot_irf(IRF_CB[,,,,2])
#'
#' @export
irf_mrvar_nm_cb <- function (RESS, nstep, comb, irf = c("gen", "chol", "chol1", "gen1", "comb1"), runs = 200, conf = c(0.05, 0.95)) {
  n = RESS$n
  p = RESS$p
  T = dim(RESS$Y)[1]
  S = RESS$S
  SESVI = RESS$SESVI
  TH = RESS$TH
  Bo = RESS$Bo
  Co = RESS$Co
  Sigmao = RESS$Sigmao
  SV = RESS$SV
  if (is.null(SV))
    SV = NA
  type = RESS$type
  X = RESS$X
  if (is.null(X))
    X = NA
  mu = RESS$mu
  if (is.null(mu))
    mu = NA
  Yo = RESS$Yo
  if (is.null(Yo))
    Yo = NA
  Do = RESS$Do
  if (is.null(Do))
    Do = NA
  Uo_run = RESS$Uo
  neq = dim(Bo)[1]
  nvar = dim(Bo)[2]
  U_run = Uo_run * 0
  response <- array(0, dim = c(neq, nvar, nstep, length(conf) + 1, S))
  response[, , , 1, ] <- irf_mrvar_nm(RESS, nstep, comb, irf)
  responseR <- array(0, dim = c(neq, nvar, nstep, runs, S))
  for (i in 1:runs) {
    for (s in 1:S) {
      U_run[, , s] = rnorm_sigma(T, Sigmao[, , s])
      B = Bo[, , 1:p[s, 1], s]
      if (length(dim(B)) == 2)
        dim(B) = c(dim(B), 1)
      res_run = var_data(n = n, p = p[s, 1], T = T, B = B,
                         Co = 0 * (1:n), Sigma = Sigmao[, , s], U = U_run[, , s], type = "none")
      res_e = var_estimate(res_run)
      responseR[, , , i, s] <- irf_from_params(res_e$B, res_e$Sigma, nstep, comb, irf)
    }
  }
  for (tt in 1:(nstep)) {
    for (i in 1:neq) {
      for (j in 1:nvar) {
        for (s in 1:S) response[i, j, tt, -1, s] = stats::quantile(responseR[i, j, tt, , s], conf)
      }
    }
  }
  return(response)
}



#' Calculate Regime Specific Impulse Response Functions with Confidence Bands for MRVAR Models
#'
#' This function calculates the regime specific impulse response functions of an estimated MRVAR(n,p,S),
#' using the Bo\[,,,s\] and Sigma\[,,s\] matrices of the estimated MRVAR. It also provides bootstrapped 
#' confidence intervals for the impulse response functions.
#'
#' @param res_e an output of MRVARest.
#' @param nstep the length of impulse response function
#' @param comb a vector specifying the concerted action in policy-simulation impulse response function
#' @param irf types of the impulse response functions. irf=c("gen","chol","chol1","gen1","comb1"), 
#'            gen for generalized IRF with one standard deviation shocks, 
#'            gen1 for generalized IRF with one unit impulse, 
#'            chol for IRF with Cholezky decomposition of the covariance matrix, 
#'            chol1 for Cholezky decomposition with one unit impulse, 
#'            comb1 for concerted action with one unit impulse in GVAR.
#' @param Xshks number of selected exogenous shocks
#' @param runs number of simulation runs
#' @param conf a two components vector containing the tail probabilities of the bootstrap confidence interval.
#' @return an (n,n,nstep,3,2) array containing the IRF of the two regimes. The IRF columns represent the impulse and the rows the responses.
#' @examples
#' p = matrix(c(2,1,0,0),2,2)
#' res_d = mrvar_data(n=2,p=p,T=300,S=2,SESVI=1)
#' max(abs(res_d$Y))
#' res_e  = mrvar_estimate(res_d)
#' res_e$Summary
#'
#' IRF_CB = irf_mrvar_cb(res_e,nstep=20,comb=NA,irf="gen1",runs=100,conf=c(0.05,0.90))
#' IRF_list1 <- plot_irf(IRF_CB[[1]])
#' IRF_list2 <- plot_irf(IRF_CB[[2]])
#'
#' @export
irf_mrvar_cb <- function (res_e, nstep, comb, irf = c("gen", "chol", "chol1", "gen1", "comb1", "irfX"), Xshks=NA, runs = 200, conf = c(0.05, 0.95)) {
  n = res_e$n
  p = res_e$p
  T = dim(res_e$Y)[1]
  S = res_e$S
  SV = res_e$SV
  SESVI = res_e$SESVI
  TH = res_e$TH
  Sigmao = res_e$Sigmao
  Bo = res_e$Bo
  Co = res_e$Co
  type = res_e$type
  r = res_e$r
  Uo = res_e$Uo
  Y = res_e$Y
  X = res_e$X

  Xshk1 = NA
  Xshk2 = NA
  if (irf=="irfX") {
    Xshk1 = t(Co[,1+Xshks,1])
    Xshk2 = t(Co[,1+Xshks,2])
  }

  IRF1 = irf_from_params(B = res_e$Bo[, , , 1], sigma = res_e$Sigma[,, 1], nstep = nstep, comb = NA, irf = irf, G = NA, smat = NA,Xshk=Xshk1)
  IRF2 = irf_from_params(B = res_e$Bo[, , , 2], sigma = res_e$Sigma[,, 2], nstep = nstep, comb = NA, irf = irf, G = NA, smat = NA,Xshk=Xshk2)

  neq = res_e$n
  nvar = res_e$n
  response1 <- array(0, dim = c(neq, nvar, nstep, length(conf) + 1))
  response2 <- array(0, dim = c(neq, nvar, nstep, length(conf) + 1))
  response1[, , , 1] <- IRF1
  response2[, , , 1] <- IRF2
  responseR <- array(0, dim = c(neq, nvar, nstep, runs, S))
  BoColect = array(0, c(dim(Bo), runs))
  UoColect = array(0, c(dim(Uo), runs))
  CoColect = array(0, c(dim(Co), runs))
  YColect = array(0, c(dim(Y), runs))
  Uo_run = array(0, c(T, n, S))

  for (i in 1:runs) {
    for (s in 1:S) Uo_run[, , s] = rnorm_sigma(T, Sigmao[,, s])
    if (length(p) > 1) {
      res_run = mrvar_data(n = n, p = p, T = T, S = S, SESVI = SESVI, TH = TH, Bo = Bo, Co = Co, Sigmao = Sigmao, Uo = Uo_run, type = type, X = X)
      res_e_run = mrvar_estimate(res = res_run)
    }
    Co_run <- res_e_run$Co
    Xshk1_run = NA
    Xshk2_run = NA

    if (irf == "irfX") {
      Xshk1_run = t(Co_run[,1+Xshks,1])
      Xshk2_run = t(Co_run[,1+Xshks,2])
    }
    IRF1 = irf_from_params(B = res_e_run$Bo[, , , 1], sigma = res_e_run$Sigma[, , 1], nstep = nstep, comb = NA, irf = irf, G = NA,Xshk=Xshk1_run)
    IRF2 = irf_from_params(B = res_e_run$Bo[, , , 2], sigma = res_e_run$Sigma[, , 2], nstep = nstep, comb = NA, irf = irf, G = NA,Xshk=Xshk2_run)
    responseR[, , , i, 1] <- IRF1
    responseR[, , , i, 2] <- IRF2
    BoColect[, , , , i] <- res_e_run$Bo
    CoColect[, , , i] <- res_e_run$Co
    UoColect[, , , i] <- res_run$Uo
    YColect[, , i] <- res_run$Y
  }

  for (tt in 1:(nstep)) {
    for (i in 1:neq) {
      for (j in 1:nvar) {
        response1[i, j, tt, -1] = stats::quantile(responseR[i,
                                                            j, tt, , 1], conf)
        response2[i, j, tt, -1] = stats::quantile(responseR[i,
                                                            j, tt, , 2], conf)
      }
    }
  }
  return(list(response1, response2, BoColect, UoColect, YColect))
}



#'
#' Calculate Bootstrapped Confidence Intervals for Impulse Response Functions of VAR Models
#'
#' This function generates impulse response functions of an estimated VAR(p) model, 
#' providing bootstrapped confidence intervals for the impulse response functions.
#'
#' @param res an object of the output of var_estimate
#' @param nstep length of the impulse response functions
#' @param comb a vector containing the weights of a combined policy actions
#' @param irf types of impulse response functions
#' @param runs number of simulation runs in generating the confidence interval of the impulse response functions
#' @param conf confidence levels
#' @param smat shock to response transformation matrix for the option irf="smat"
#' @param Xshks the number of exogenous variables
#'
#' @return an (n, n, nstep, 3) array containing the impulse response functions
#' @examples
#' res_d = var_data(n=2,p=2,T=100,type="const")
#' res_e = var_estimate(res=res_d)
#' IRF_CB = irf_var_cb(res=res_e,nstep=20, comb=NA, irf = "gen1", runs = 100, conf = c(0.05, 0.95))
#' IRF_list <- plot_irf(IRF_CB)
#' res_e$Summary
#'
#' @export
irf_var_cb <- function (res, nstep, comb, irf = c("gen", "chol", "chol1", "gen1", "comb1","irfX"), runs = 200, conf = c(0.05, 0.95), smat = NA, Xshks = NA) {
  n = res$n
  p = res$p
  T = dim(res$Y)[1]
  A = res$A
  B = res$B
  Co = res$Co
  type = res$type
  X = res$X
  crk = res$crk
  neq = dim(B)[1]
  nvar = dim(B)[2]
  sigma = res$Sigma
  response <- array(0, dim = c(neq, nvar, nstep, length(conf) + 1))
  
  if (irf == "irfX") { 
    Xshk = t(Co[, 1 + Xshks]) 
  }
  
  response[, , , 1] <- irf_from_params(B = B, sigma = sigma, nstep, comb, irf, G = NA, A0 = NA, B0 = NA, smat, Xshk)
  responseR <- array(0, dim = c(neq, nvar, nstep, runs))
  
  for (i in 1:runs) {
    Uo_run = rnorm_sigma(T, sigma)
    res_run = var_data(n, p, T, r_np = NA, A = NA, B, Co, U = Uo_run, Sigma = NA, type, X, mu = NA, Yo = NA)
    res_e = var_estimate(res = res_run)
    B_run = res_e$B
    Co_run = res_e$Co
    sigma_run = res_e$Sigma
    
    if (irf == "irfX") { 
      Xshk = t(Co_run[, 1 + Xshks]) 
    }
    
    responseR[, , , i] <- irf_from_params(B = res_e$B, sigma = res_e$Sigma, nstep, comb, irf, G = NA, A0 = NA, B0 = NA, smat, Xshk)
  }
  
  for (tt in 1:(nstep)) {
    for (i in 1:neq) {
      for (j in 1:nvar) {
        response[i, j, tt, -1] = stats::quantile(responseR[i, j, tt, ], conf)
      }
    }
  }
  
  return(response)
}



#'
#' Generate Impulse Response Functions from Model Parameters
#'
#' This function generates impulse response functions for various types of models including VAR, CIVAR, MRVAR, MRCIVAR, GVAR, CIGVAR, MRGVAR, and MRCIGVAR. 
#' It also provides functionalities to calculate global, regional, and country-specific shocks, as well as global and regional responses and coordinated policy actions.
#'
#' @param B An (nxnxp) coefficients array of an n-dimensional VAR(p) model
#' @param sigma The covariance matrix of the VAR(p) model
#' @param nstep Number of steps of the impulse response function
#' @param comb An n-vector of weights of the coordinated policy actions
#' @param irf Type of impulse response function
#' @param G The matrix used in the permanent and transitory decomposition
#' @param A0 The matrix for A/B identification in VAR
#' @param B0 The matrix for A/B identification in VAR
#' @param smat An explicit decomposition matrix that defines a structural shock.
#' @param Xshk The shock matrix of a one unit exogenous shock
#'
#' @export
irf_from_params <- function (B, sigma, nstep, comb, irf = c("gen", "chol",
                              "chol1", "gen1", "genN1", "comb1",
                              "smat", "concerts1","PTdecomp","ABSVAR","irfX"), 
               G = NA, A0=NA, B0=NA, smat=NA, Xshk=NA) {
  neq <- dim(B)[1]
  nvar <- dim(B)[2]
  lags <- dim(B)[3]
  n = dim(sigma)[1]
  
  if (irf == "irfX") {
  smat = matrix(0, n, n)
  smat[1:nrow(Xshk),] = Xshk
  }

  if (irf == "smat") {
  smat = (smat)
  }
  if (irf == "chol") {
  smat = chol(sigma)
  }
  if (irf == "PTdecomp") {
  smat = t(solve(G) %*% t(chol(G %*% sigma %*% t(G))))
  }
  if (irf == "ABSVAR") {
  smat = t(solve(A0) %*% B0)
  }
  if (irf == "gen") {
  smat = t(sigma %*% diag(1/(sqrt(diag(sigma)))))
  }
  if (irf == "chol1") {
  smat = chol(sigma) %*% diag(1/diag(chol(sigma)))
  }
  if (irf == "gen1") {
  smat = t(sigma %*% diag(1/(diag(sigma))))
  }
  if (irf == "genN1") {
  smat = t(sigma %*% diag(-1/(diag(sigma))))
  }
  if (irf == "concerts1") {
  smat = t((sigma %*% diag(1/(diag(sigma)))) %*% comb)
  }
  if (irf == "concerts0") {
  smat = t((sigma %*% diag(1/(sqrt(diag(sigma))))) %*% comb)
  }
  if (irf == "concertc") {
  c = as.numeric(!(comb[, 1] == 0))
  smat = matrix(0, n, n)
  for (i in 1:n) {
    smat[i, ] = sigma[i, ] %*% diag(c) %*% invi(sigma, c, i) %*% comb
  }
  smat = t(smat)
  }
  if (irf == "comb") {
  DD = diag(t(comb) %*% sigma %*% comb)
  for (i in 1:length(DD)) {
    if (DD[i] > 0)
    DD[i] = sqrt(1/DD[i])
  }
  DD = diag(DD)
  smat = t(sigma %*% comb %*% DD)
  }
  if (irf == "comb1") {
  DD = diag(t(comb) %*% sigma %*% comb)
  for (i in 1:length(DD)) {
    if (DD[i] > 0)
    DD[i] = (1/DD[i])
  }
  DD = diag(DD)
  smat = t(sigma %*% comb %*% DD)
  }
  
  if (dim(smat)[2] != dim(B)[2])
  stop("B and smat conflict on # of variables")
  
  response <- array(0, dim = c(neq, nvar, nstep))
  response[, , 1] <- t(smat)
  
  for (it in 2:nstep) {
  for (ilag in 1:min(lags, it - 1)) 
    response[, , it] <- response[, , it] + B[, , ilag] %*% response[, , it - ilag]
  }
  
  dimnames(response) <- list(dimnames(B)[[2]], dimnames(smat)[[1]], as.character(0:(nstep - 1)))
  
  # @examples
  # B = array(runif(8), dim = c(2, 2, 2))
  # sigma = diag(2)
  # nstep = 10
  # comb = c(1, 0)
  # irf = "gen"
  # response = irf_from_params(B, sigma, nstep, comb, irf)
  
  return(response)
}



#'
#' Plot impulse responses with confidence bands
#'
#' Create a grid of `ggplot2` impulse response plots from an IRF array with
#' confidence bands.
#'
#' @param IRF_CB Four-dimensional IRF array, typically with dimensions `(n, n,
#'   horizon, band)`.
#' @param Names Character vector of response-variable names.
#' @param INames Character vector of impulse names.
#' @param response Integer vector selecting the response indices to plot.
#' @param impulse Integer vector selecting the impulse indices to plot.
#' @param ncol Integer scalar giving the number of columns in the plot layout.
#' @return A list of `ggplot2` objects, invisibly arranged into a grid as a side
#'   effect.
#' @export
#' @keywords internal
plot_irf <- function(IRF_CB = IRF_CB, Names = NA, INames = NA, response = c(1:n), impulse = c(1:n), ncol = n) {
  ### This function create a list of ggplot objects for the impulse response functions
  IRF_list = list()
  n = dim(IRF_CB)[1]
  
  if (anyNA(Names)) Names <- colnames(IRF_CB)
  if (is.null(Names)) Names <- paste0(rep("Y", n), c(1:n))
  if (anyNA(INames)) INames <- Names

  k = 0
  for (i in response) {
    for (j in impulse) {
      k = k + 1
      myData <- as.data.frame(cbind(c(0:(dim(IRF_CB)[3] - 1)), IRF_CB[i, j, , ]))
      V1 = 1; V2 = 1; V3 = 1; V4 = 1
      IRF_list[[k]] <- ggplot2::ggplot(myData,
                                        ggplot2::aes(x = V1, y = V2, ymin = V3, ymax = V4)) +
        ggplot2::geom_hline(yintercept = 0, color = "red") +
        ggplot2::geom_ribbon(fill = "grey", alpha = 0.5) +
        ggplot2::geom_line() +
        ggplot2::theme_light() +
        ggplot2::ggtitle(paste(Names[i], "response to", INames[j], "shock")) +
        ggplot2::ylab("") +
        ggplot2::xlab("") +
        ggplot2::theme(plot.title = ggplot2::element_text(size = 11, hjust = 0.5), 
                       axis.title.y = ggplot2::element_text(size = 11))
    }
  }

  do.call(gridExtra::grid.arrange, c(IRF_list, ncol = ncol))
  return(IRF_list)
}
